export type Role = 'ADMIN' | 'MANAGER' | 'CASHIER' | 'KITCHEN';

export interface User {
  id: string;
  name: string;
  pin: string;
  role: Role;
}

export interface Category {
  id: string;
  name: string;
  color: string;
}

export interface Ingredient {
  id: string;
  name: string;
  unit: 'kg' | 'g' | 'L' | 'ml' | 'unit';
  currentStock: number;
  minStock: number;
  costPrice: number;
}

export interface RecipeItem {
  ingredientId: string;
  quantity: number;
}

export interface Product {
  id: string;
  categoryId: string;
  name: string;
  price: number;
  vatRate: number;
  recipe: RecipeItem[];
  imageUrl?: string;
  isAvailable: boolean;
}

export type OrderStatus = 'PENDING' | 'PREPARING' | 'READY' | 'SERVED' | 'CANCELLED';

export interface OrderItem {
  productId: string;
  quantity: number;
  price: number;
  notes?: string;
}

export interface Order {
  id: string;
  orderNumber: string;
  timestamp: number;
  items: OrderItem[];
  total: number;
  status: OrderStatus;
  paymentMethod?: 'CASH' | 'CARD' | 'OTHER';
  customerId?: string;
  location?: string;
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  email?: string;
  loyaltyPoints: number;
  lastVisit?: number;
}

export interface DailySummary {
  date: string;
  totalSales: number;
  orderCount: number;
