import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, ShoppingCart, Trash2, UserPlus, CreditCard, Banknote } from 'lucide-react';
import { PRODUCTS, CATEGORIES } from '../constants';
import { Product, OrderItem } from '../types';

interface POSProps {
  onAddOrder: (items: OrderItem[], total: number, paymentMethod: 'CASH' | 'CARD') => void;
}

const POS: React.FC<POSProps> = ({ onAddOrder }) => {
  const [activeCategoryId, setActiveCategoryId] = useState<string>(CATEGORIES[0].id);
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(p => 
      (activeCategoryId === 'all' || p.categoryId === activeCategoryId) &&
      p.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [activeCategoryId, searchQuery]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        return prev.map(item => 
          item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { productId: product.id, quantity: 1, price: product.price }];
    });
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.productId === productId) {
        const newQty = Math.max(0, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const cartTotal = useMemo(() => {
    return cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  }, [cart]);

  const handleCheckout = (method: 'CASH' | 'CARD') => {
    if (cart.length === 0) return;
    onAddOrder(cart, cartTotal, method);
    setCart([]);
  };

  return (
    <div className="flex h-[calc(100vh-64px)] overflow-hidden">
      {/* Products Grid */}
      <div className="flex-1 p-4 md:p-6 overflow-y-auto space-y-6">
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
          <div className="relative w-full md:w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher un produit..."
              className="w-full pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 outline-none"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto pb-2 w-full md:w-auto scrollbar-hide">
            <button 
              onClick={() => setActiveCategoryId('all')}
              className={`px-4 py-2 rounded-xl text-sm font-bold whitespace-nowrap transition ${
                activeCategoryId === 'all' ? 'bg-orange-600 text-white shadow-lg' : 'bg-white text-gray-600 border border-gray-100'
              }`}
            >
              Tous
            </button>
            {CATEGORIES.map(cat => (
              <button 
                key={cat.id}
                onClick={() => setActiveCategoryId(cat.id)}
                className={`px-4 py-2 rounded-xl text-sm font-bold whitespace-nowrap transition ${
                  activeCategoryId === cat.id ? 'bg-orange-600 text-white shadow-lg' : 'bg-white text-gray-600 border border-gray-100'
                }`}
              >
                {cat.name}
              </button>
            ))}
          </div>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {filteredProducts.map(product => (
            <button 
              key={product.id}
              onClick={() => addToCart(product)}
              className="bg-white p-3 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md hover:border-orange-200 transition text-left group flex flex-col h-full"
            >
              <div className="relative aspect-square overflow-hidden rounded-xl mb-3">
                <img src={product.imageUrl} alt={product.name} className="w-full h-full object-cover group-hover:scale-105 transition duration-300" />
                <div className="absolute top-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded-lg font-bold text-sm text-orange-600">
                  {product.price.toFixed(2)}€
                </div>
              </div>
              <h3 className="font-bold text-gray-800 line-clamp-1">{product.name}</h3>
              <p className="text-xs text-gray-500 mt-1">TVA {product.vatRate}%</p>
            </button>
          ))}
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-96 bg-white border-l border-gray-200 flex flex-col shadow-2xl">
        <div className="p-4 border-b border-gray-100 flex items-center justify-between">
          <div className="flex items-center gap-2 font-bold text-lg">
            <ShoppingCart className="text-orange-600" size={24} />
            Panier <span className="bg-orange-100 text-orange-600 text-xs px-2 py-0.5 rounded-full ml-1">{cart.length}</span>
          </div>
          <button 
            onClick={() => setCart([])}
            className="text-gray-400 hover:text-red-500 transition"
          >
            <Trash2 size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-50 space-y-3">
              <ShoppingCart size={48} strokeWidth={1} />
              <p className="text-sm font-medium">Panier vide</p>
            </div>
          ) : (
            cart.map(item => {
              const product = PRODUCTS.find(p => p.id === item.productId)!;
              return (
                <div key={item.productId} className="flex items-center gap-3 bg-gray-50 p-3 rounded-xl">
                  <div className="flex-1">
                    <p className="font-bold text-sm">{product.name}</p>
                    <p className="text-xs text-orange-600 font-bold">{(item.price * item.quantity).toFixed(2)}€</p>
                  </div>
                  <div className="flex items-center gap-2 bg-white rounded-lg p-1 border border-gray-100">
                    <button onClick={() => updateQuantity(item.productId, -1)} className="p-1 hover:bg-gray-100 rounded-md transition"><Minus size={14} /></button>
                    <span className="w-6 text-center text-sm font-bold">{item.quantity}</span>
                    <button onClick={() => updateQuantity(item.productId, 1)} className="p-1 hover:bg-gray-100 rounded-md transition"><Plus size={14} /></button>
                  </div>
                </div>
              );
            })
          )}
        </div>

        <div className="p-6 bg-gray-50 border-t border-gray-200 space-y-4">
          <button className="w-full flex items-center justify-between p-3 bg-white border border-gray-200 rounded-xl text-gray-600 hover:border-orange-500 transition">
            <div className="flex items-center gap-2 text-sm font-semibold">
              <UserPlus size={18} /> Client Fidélité
            </div>
            <span className="text-xs bg-gray-100 px-2 py-0.5 rounded-full">Optionnel</span>
          </button>

          <div className="space-y-2">
            <div className="flex justify-between text-sm text-gray-500">
              <span>Sous-total</span>
              <span>{(cartTotal / 1.1).toFixed(2)}€</span>
            </div>
            <div className="flex justify-between text-sm text-gray-500">
              <span>TVA (moyenne)</span>
              <span>{(cartTotal - (cartTotal / 1.1)).toFixed(2)}€</span>
            </div>
            <div className="flex justify-between text-xl font-black pt-2">
              <span>Total</span>
              <span className="text-orange-600">{cartTotal.toFixed(2)}€</span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <button 
              disabled={cart.length === 0}
              onClick={() => handleCheckout('CASH')}
              className="flex flex-col items-center justify-center gap-1 bg-white border-2 border-green-100 py-3 rounded-2xl hover:bg-green-50 hover:border-green-500 transition disabled:opacity-50"
            >
              <Banknote className="text-green-600" />
              <span className="text-xs font-bold text-green-700">Espèces</span>
            </button>
            <button 
              disabled={cart.length === 0}
              onClick={() => handleCheckout('CARD')}
              className="flex flex-col items-center justify-center gap-1 bg-orange-600 py-3 rounded-2xl shadow-lg shadow-orange-100 hover:bg-orange-700 transition disabled:opacity-50"
            >
              <CreditCard className="text-white" />
              <span className="text-xs font-bold text-white">Carte</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default POS;

import React from 'react';
import { Clock, CheckCircle2, AlertCircle } from 'lucide-react';
import { Order, OrderStatus } from '../types';
import { PRODUCTS } from '../constants';

interface KDSProps {
  orders: Order[];
  onStatusChange: (orderId: string, newStatus: OrderStatus) => void;
}

const KDS: React.FC<KDSProps> = ({ orders, onStatusChange }) => {
  const pendingOrders = orders.filter(o => o.status === 'PENDING' || o.status === 'PREPARING');
  const readyOrders = orders.filter(o => o.status === 'READY');

  const Ticket: React.FC<{ order: Order }> = ({ order }) => {
    const elapsed = Math.floor((Date.now() - order.timestamp) / 60000);
    const isLate = elapsed > 15;

    return (
      <div className={`bg-white rounded-2xl shadow-sm border-l-8 ${
        order.status === 'PREPARING' ? 'border-blue-500' : 'border-orange-500'
      } overflow-hidden`}>
        <div className="p-4 border-b border-gray-50 flex justify-between items-center">
          <div>
            <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">#{order.orderNumber}</span>
            <h4 className="font-black text-lg">Commande #{order.orderNumber.split('-')[1]}</h4>
          </div>
          <div className={`flex items-center gap-1 text-sm font-bold ${isLate ? 'text-red-500' : 'text-gray-500'}`}>
            <Clock size={16} /> {elapsed}m
          </div>
        </div>

        <div className="p-4 space-y-3">
          {order.items.map((item, idx) => {
            const product = PRODUCTS.find(p => p.id === item.productId);
            return (
              <div key={idx} className="flex justify-between items-start">
                <div className="flex gap-3">
                  <span className="w-6 h-6 flex items-center justify-center bg-gray-100 rounded text-sm font-bold">{item.quantity}</span>
                  <span className="font-bold text-gray-800">{product?.name}</span>
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-3 bg-gray-50">
          {order.status === 'PENDING' ? (
            <button 
              onClick={() => onStatusChange(order.id, 'PREPARING')}
              className="w-full bg-blue-600 text-white py-2 rounded-xl font-bold hover:bg-blue-700 transition"
            >
              Lancer préparation
            </button>
          ) : (
            <button 
              onClick={() => onStatusChange(order.id, 'READY')}
              className="w-full bg-green-600 text-white py-2 rounded-xl font-bold hover:bg-green-700 transition flex items-center justify-center gap-2"
            >
              <CheckCircle2 size={18} /> Prêt
            </button>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="p-6 h-[calc(100vh-64px)] grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 overflow-x-auto">
      {/* Pending / Preparing Column */}
      <div className="flex flex-col gap-4 min-w-[300px]">
        <h2 className="text-xl font-black flex items-center gap-2 sticky top-0 bg-gray-50 py-2 z-10">
          En Cours <span className="text-sm bg-orange-100 text-orange-600 px-2 rounded-full">{pendingOrders.length}</span>
        </h2>
        <div className="space-y-4">
          {pendingOrders.map(order => <Ticket key={order.id} order={order} />)}
          {pendingOrders.length === 0 && (
            <div className="p-12 text-center text-gray-400">
              <CheckCircle2 className="mx-auto mb-2 opacity-20" size={48} />
              <p>Aucune commande</p>
            </div>
          )}
        </div>
      </div>

      {/* Ready Column */}
      <div className="flex flex-col gap-4 min-w-[300px]">
        <h2 className="text-xl font-black flex items-center gap-2 sticky top-0 bg-gray-50 py-2 z-10">
          Prêt pour retrait <span className="text-sm bg-green-100 text-green-600 px-2 rounded-full">{readyOrders.length}</span>
        </h2>
        <div className="space-y-4">
          {readyOrders.map(order => (
            <div key={order.id} className="bg-white p-4 rounded-2xl border border-green-100 shadow-sm flex justify-between items-center animate-pulse">
              <div>
                <p className="font-black text-xl">#{order.orderNumber}</p>
                <p className="text-sm text-gray-500">Prêt depuis {Math.floor((Date.now() - order.timestamp)/60000)}m</p>
              </div>
              <button 
                onClick={() => onStatusChange(order.id, 'SERVED')}
                className="bg-green-100 text-green-600 px-4 py-2 rounded-xl font-bold hover:bg-green-200"
              >
                Servi
              </button>
            </div>
          ))}
          {readyOrders.length === 0 && (
            <div className="p-12 text-center text-gray-400">
              <p>Rien en attente</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default KDS;

import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import KDS from './components/KDS';
import Inventory from './components/Inventory';
import { Order, OrderItem, OrderStatus, Ingredient } from './types';
import { MOCK_ORDERS, INGREDIENTS, PRODUCTS } from './constants';
import { Bell, Search, Settings as SettingsIcon } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('dashboard');
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [ingredients, setIngredients] = useState<Ingredient[]>(INGREDIENTS);

  // Business Logic: Automatic Stock Reduction
  const processStockReduction = (items: OrderItem[]) => {
    setIngredients(prev => {
      const next = [...prev];
      items.forEach(item => {
        const product = PRODUCTS.find(p => p.id === item.productId);
        if (product && product.recipe) {
          product.recipe.forEach(recipeItem => {
            const ingIdx = next.findIndex(i => i.id === recipeItem.ingredientId);
            if (ingIdx !== -1) {
              next[ingIdx] = {
                ...next[ingIdx],
                currentStock: next[ingIdx].currentStock - (recipeItem.quantity * item.quantity)
              };
            }
          });
        }
      });
      return next;
    });
  };

  const handleAddOrder = (items: OrderItem[], total: number, paymentMethod: 'CASH' | 'CARD') => {
    const newOrder: Order = {
      id: `o-${Date.now()}`,
      orderNumber: `MT-${orders.length + 101}`,
      timestamp: Date.now(),
      items,
      total,
      status: 'PENDING',
      paymentMethod,
    };
    setOrders(prev => [newOrder, ...prev]);
    processStockReduction(items);
    setCurrentView('kds'); // Direct flow to kitchen after order
  };

  const updateOrderStatus = (orderId: string, newStatus: OrderStatus) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard />;
      case 'pos': return <POS onAddOrder={handleAddOrder} />;
      case 'kds': return <KDS orders={orders} onStatusChange={updateOrderStatus} />;
      case 'inventory': return <Inventory />;
      case 'customers':
        return (
          <div className="p-12 text-center text-gray-400">
            <h2 className="text-2xl font-bold mb-4">Module Clients & Fidélité</h2>
            <p>Disponible dans la version pro.</p>
          </div>
        );
      case 'orders':
        return (
          <div className="p-6">
            <h2 className="text-2xl font-black mb-6">Historique des commandes</h2>
            <div className="bg-white rounded-2xl border border-gray-100 overflow-hidden shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-gray-50 font-bold text-gray-500 uppercase text-xs tracking-widest">
                  <tr>
                    <th className="px-6 py-4">N° Commande</th>
                    <th className="px-6 py-4">Heure</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Paiement</th>
                    <th className="px-6 py-4 text-right">Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {orders.map(o => (
