import { useState, useMemo } from 'react';
import { ProduitPanier, CalculTotaux } from '../types';
import { calculerTotaux } from '@shared/utils/calculations';

export function usePanier() {
  const [items, setItems] = useState<ProduitPanier[]>([]);

  const ajouterProduit = (
    produit: Produit,
    variantes: Variante[] = [],
    quantite: number = 1
  ) => {
    const prixVariantes = variantes.reduce((sum, v) => sum + v.prixSupplement, 0);
    const prixUnitaire = produit.prixVente + prixVariantes;

    const item: ProduitPanier = {
      id: crypto.randomUUID(),
      produit,
      quantite,
      variantesSelectionnees: variantes,
      prixUnitaire,
      prixTotal: prixUnitaire * quantite,
    };

    setItems(prev => [...prev, item]);
  };

  const retirerProduit = (index: number) => {
    setItems(prev => prev.filter((_, i) => i !== index));
  };

  const viderPanier = () => {
    setItems([]);
  };

  const modifierQuantite = (index: number, quantite: number) => {
    setItems(prev => prev.map((item, i) => 
      i === index 
        ? { ...item, quantite, prixTotal: item.prixUnitaire * quantite }
        : item
    ));
  };

  const total: CalculTotaux = useMemo(() => 
    calculerTotaux(items),
    [items]
  );

  return {
    items,
    ajouterProduit,
    retirerProduit,
    viderPanier,
    modifierQuantite,
    total,
  };
}

