  ingredients: Ingredient[];
  onAddOrder: (items: CartItem[], total: number, paymentMethod: 'CASH' | 'CARD') => void;
}

const POS: React.FC<POSProps> = ({ ingredients, onAddOrder }) => {
  const [activeCategoryId, setActiveCategoryId] = useState<string>(CATEGORIES[0].id);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  const isProduitDisponible = (produit: Product) => {
    if (!produit.recipe || produit.recipe.length === 0) return true;
    return produit.recipe.every(item => {
      const ingredient = ingredients.find(i => i.id === item.ingredientId);
      return ingredient && ingredient.currentStock >= item.quantity;
    });
  };

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(p => 
      (activeCategoryId === 'all' || p.categoryId === activeCategoryId) &&
      p.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [activeCategoryId, searchQuery]);

  const addToCart = (product: Product, variants: Variant[] = []) => {
    const prixVariantes = variants.reduce((sum, v) => sum + v.priceExtra, 0);
    const unitPrice = product.price + prixVariantes;

    const newItem: CartItem = {
      id: crypto.randomUUID(),
      productId: product.id,
      product,
      quantity: 1,
      selectedVariants: variants,
      unitPrice,
      totalPrice: unitPrice,
    };

    setCart(prev => [...prev, newItem]);
    setSelectedProduct(null);
  };

  const removeCartItem = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty, totalPrice: item.unitPrice * newQty };
      }
      return item;
    }));
  };

  const totals = useMemo(() => calculerTotaux(cart), [cart]);

  return (
    <div className="flex h-[calc(100vh-64px)] overflow-hidden">
      {/* Products Grid */}
      <div className="flex-1 p-4 md:p-6 overflow-y-auto space-y-6">
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
          <div className="relative w-full md:w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher un produit..."
              className="w-full pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 outline-none shadow-sm"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto pb-2 w-full md:w-auto scrollbar-hide">
            <button 
              onClick={() => setActiveCategoryId('all')}
              className={`px-5 py-2.5 rounded-xl text-sm font-bold whitespace-nowrap transition-all ${
                activeCategoryId === 'all' ? 'bg-orange-600 text-white shadow-lg' : 'bg-white text-gray-600 border border-gray-200'
              }`}
            >
              Tous
            </button>
            {CATEGORIES.map(cat => (
              <button 
                key={cat.id}
                onClick={() => setActiveCategoryId(cat.id)}
                className={`px-5 py-2.5 rounded-xl text-sm font-bold whitespace-nowrap transition-all ${
                  activeCategoryId === cat.id ? 'bg-orange-600 text-white shadow-lg' : 'bg-white text-gray-600 border border-gray-200'
                }`}
              >
                {cat.name}
              </button>
            ))}
          </div>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5">
          {filteredProducts.map(product => {
            const disponible = isProduitDisponible(product);
            return (
              <button 
                key={product.id}
                disabled={!disponible}
                onClick={() => product.variants ? setSelectedProduct(product) : addToCart(product)}
                className={`bg-white p-3 rounded-2xl border border-gray-100 shadow-sm transition-all text-left group flex flex-col h-full relative ${
                  disponible ? 'hover:shadow-xl hover:border-orange-200 active:scale-95' : 'opacity-60 grayscale cursor-not-allowed'
                }`}
              >
                <div className="relative aspect-square overflow-hidden rounded-xl mb-3 bg-gray-100">
                  <img src={product.imageUrl} alt={product.name} className="w-full h-full object-cover transition duration-500 group-hover:scale-110" />
                  <div className="absolute top-2 right-2 bg-white/95 backdrop-blur-sm px-2.5 py-1 rounded-lg font-black text-sm text-orange-600 shadow-sm">
                    {formatPrix(product.price)}
                  </div>
                  {!disponible && (
                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                       <span className="bg-red-600 text-white text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-tighter">Épuisé</span>
                    </div>
                  )}
                </div>
                <h3 className="font-bold text-gray-800 line-clamp-2 text-sm leading-tight">{product.name}</h3>
                <div className="mt-auto pt-2 flex items-center justify-between">
                  <span className="text-[10px] text-gray-400 font-bold uppercase">TVA {product.vatRate}%</span>
                  {product.variants && <span className="text-[10px] bg-blue-50 text-blue-600 px-1.5 rounded font-bold">Options</span>}
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-96 bg-white border-l border-gray-200 flex flex-col shadow-2xl z-10">
        <div className="p-4 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
          <div className="flex items-center gap-2 font-black text-lg text-gray-800">
            <ShoppingCart className="text-orange-600" size={24} />
            PANIER <span className="bg-orange-600 text-white text-[10px] h-5 w-5 flex items-center justify-center rounded-full ml-1">{cart.length}</span>
          </div>
          <button 
            onClick={() => setCart([])}
            className="text-gray-400 hover:text-red-500 transition-colors p-2 hover:bg-red-50 rounded-lg"
          >
            <Trash2 size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-400/50 space-y-4">
              <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center border-2 border-dashed border-gray-200">
                <ShoppingCart size={40} strokeWidth={1} />
              </div>
              <p className="text-sm font-bold uppercase tracking-widest">Panier vide</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex flex-col bg-gray-50 p-3 rounded-2xl border border-gray-100 animate-in slide-in-from-right-4 duration-200">
                <div className="flex items-center gap-3">
                  <div className="flex-1">
                    <p className="font-bold text-sm text-gray-800">{item.product.name}</p>
                    {item.selectedVariants.length > 0 && (
                      <p className="text-[10px] text-gray-500 font-medium">
                        {item.selectedVariants.map(v => v.name).join(', ')}
                      </p>
                    )}
                    <p className="text-xs text-orange-600 font-black mt-1">{formatPrix(item.totalPrice)}</p>
                  </div>
                  <div className="flex items-center gap-2 bg-white rounded-xl p-1 shadow-sm border border-gray-100">
                    <button onClick={() => updateQuantity(item.id, -1)} className="p-1.5 hover:bg-gray-100 rounded-lg transition-colors"><Minus size={14} /></button>
                    <span className="w-6 text-center text-sm font-black">{item.quantity}</span>
                    <button onClick={() => updateQuantity(item.id, 1)} className="p-1.5 hover:bg-gray-100 rounded-lg transition-colors"><Plus size={14} /></button>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Totals Section */}
        <div className="p-5 bg-white border-t border-gray-200 space-y-4">
          <div className="space-y-2.5">
            <div className="flex justify-between text-xs font-bold text-gray-400 uppercase tracking-wider">
              <span>Sous-total HT</span>
              <span>{formatPrix(totals.totalHT)}</span>
            </div>
            {Object.entries(totals.detailTVA).map(([taux, data]) => (
              <div key={taux} className="flex justify-between text-[10px] font-medium text-gray-400 italic">
                <span>TVA ({taux}%)</span>
                <span>{formatPrix(data.montantTVA)}</span>
              </div>
            ))}
            <div className="h-px bg-gray-100 my-2"></div>
            <div className="flex justify-between text-2xl font-black text-gray-900">
              <span>Total</span>
              <span className="text-orange-600">{formatPrix(totals.totalTTC)}</span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3 pt-2">
            <button 
              disabled={cart.length === 0}
              onClick={() => onAddOrder(cart, totals.totalTTC, 'CASH')}
              className="flex flex-col items-center justify-center gap-1.5 bg-white border-2 border-green-500/20 py-4 rounded-2xl hover:bg-green-50 hover:border-green-500 transition-all disabled:opacity-50 disabled:grayscale"
            >
              <Banknote className="text-green-600" size={24} />
              <span className="text-[10px] font-black text-green-700 uppercase">Espèces</span>
            </button>
            <button 
              disabled={cart.length === 0}
              onClick={() => onAddOrder(cart, totals.totalTTC, 'CARD')}
              className="flex flex-col items-center justify-center gap-1.5 bg-orange-600 py-4 rounded-2xl shadow-lg shadow-orange-100 hover:bg-orange-700 active:scale-95 transition-all disabled:opacity-50"
            >
              <CreditCard className="text-white" size={24} />
              <span className="text-[10px] font-black text-white uppercase">Carte</span>
            </button>
          </div>
        </div>
      </div>

      {/* Product Options Modal */}
      {selectedProduct && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-md overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center">
              <h2 className="text-xl font-black">{selectedProduct.name}</h2>
              <button onClick={() => setSelectedProduct(null)} className="text-gray-400 hover:text-gray-600">
                <Trash2 size={20} />
              </button>
            </div>
            <div className="p-6 space-y-6">
              <div>
                <h3 className="text-xs font-black text-gray-400 uppercase mb-3">Options Disponibles</h3>
                <div className="space-y-2">
                  {selectedProduct.variants?.map(v => (
                    <button 
                      key={v.id}
                      onClick={() => addToCart(selectedProduct, [v])}
