              </div>
              <button 
                onClick={() => addToCart(selectedProduct, [])}
                className="w-full py-4 text-sm font-black text-gray-500 hover:text-gray-800 transition-colors"
              >
                Continuer sans options
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import KDS from './components/KDS';
import Inventory from './components/Inventory';
import { Order, CartItem, OrderStatus, Ingredient } from './types';
import { MOCK_ORDERS, INGREDIENTS, PRODUCTS } from './constants';
import { Bell, ShoppingBag } from 'lucide-react';
import { formatPrix } from './utils';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('dashboard');
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [ingredients, setIngredients] = useState<Ingredient[]>(INGREDIENTS);

  // Business Logic: Automatic Stock Reduction using detailed recipe
  const processStockReduction = (items: CartItem[]) => {
    setIngredients(prev => {
      const next = [...prev];
      items.forEach(item => {
        const product = item.product;
        if (product.recipe) {
          product.recipe.forEach(recipeItem => {
            const ingIdx = next.findIndex(i => i.id === recipeItem.ingredientId);
            if (ingIdx !== -1) {
              next[ingIdx] = {
                ...next[ingIdx],
                currentStock: Number((next[ingIdx].currentStock - (recipeItem.quantity * item.quantity)).toFixed(2))
              };
            }
          });
        }
      });
      return next;
    });
  };

  const handleAddOrder = (items: CartItem[], total: number, paymentMethod: 'CASH' | 'CARD') => {
    const newOrder: Order = {
      id: `o-${Date.now()}`,
      orderNumber: `MT-${orders.length + 101}`,
      timestamp: Date.now(),
      items,
      total,
      status: 'PENDING',
      paymentMethod,
    };
    setOrders(prev => [newOrder, ...prev]);
    processStockReduction(items);
    setCurrentView('kds');
  };

  const updateOrderStatus = (orderId: string, newStatus: OrderStatus) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard />;
      case 'pos': return <POS ingredients={ingredients} onAddOrder={handleAddOrder} />;
      case 'kds': return <KDS orders={orders} onStatusChange={updateOrderStatus} />;
      case 'inventory': return <Inventory ingredients={ingredients} />;
      case 'orders':
        return (
          <div className="p-6 animate-in fade-in">
            <h2 className="text-2xl font-black mb-6">Historique des commandes</h2>
            <div className="bg-white rounded-3xl border border-gray-100 overflow-hidden shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-gray-50/50 font-black text-gray-400 uppercase text-[10px] tracking-widest border-b border-gray-50">
                  <tr>
                    <th className="px-6 py-4">Commande</th>
                    <th className="px-6 py-4">Heure</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Paiement</th>
                    <th className="px-6 py-4 text-right">Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {orders.length === 0 ? (
                    <tr><td colSpan={5} className="p-12 text-center text-gray-400 font-bold uppercase text-xs tracking-widest">Aucune donnée</td></tr>
                  ) : orders.map(o => (
                    <tr key={o.id} className="hover:bg-gray-50/50 transition-colors">
                      <td className="px-6 py-4 font-black text-gray-800">#{o.orderNumber}</td>
                      <td className="px-6 py-4 text-gray-500 text-sm font-medium">{new Date(o.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2.5 py-1 rounded-full text-[10px] font-black uppercase border ${
                          o.status === 'SERVED' ? 'bg-green-50 text-green-600 border-green-100' : 'bg-orange-50 text-orange-600 border-orange-100'
                        }`}>{o.status === 'PENDING' ? 'En attente' : o.status === 'SERVED' ? 'Servi' : 'Prêt'}</span>
                      </td>
                      <td className="px-6 py-4 text-xs font-bold text-gray-400 italic">{o.paymentMethod === 'CARD' ? 'CB' : 'Espèces'}</td>
                      <td className="px-6 py-4 text-right font-black text-gray-900">{formatPrix(o.total)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );
      default: return (
        <div className="p-12 text-center text-gray-400">
           <h2 className="text-2xl font-bold mb-4">Module en développement</h2>
           <p>Cette fonctionnalité sera disponible prochainement.</p>
        </div>
      );
    }
  };

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900 overflow-hidden">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} />

      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Header */}
        <header className="h-16 bg-white border-b border-gray-100 px-6 flex items-center justify-between sticky top-0 z-20">
          <div className="flex items-center gap-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">
            <span className="hidden sm:inline">Marché des Halles</span>
            <div className="flex items-center gap-1.5">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              <span className="text-green-500">Service Ouvert</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button className="relative p-2 text-gray-400 hover:text-orange-600 transition-colors">
              <Bell size={20} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
            </button>
            <div className="h-8 w-px bg-gray-100"></div>
            <button className="flex items-center gap-3 hover:bg-gray-50 px-3 py-1.5 rounded-xl transition-all group border border-transparent hover:border-gray-100">
              <div className="w-8 h-8 rounded-full bg-orange-600 text-white flex items-center justify-center font-black text-xs">JD</div>
              <div className="hidden md:block text-left">
                <p className="text-xs font-black text-gray-800 leading-none">M. Dupont</p>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter">Admin</p>
              </div>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto bg-[#FBFBFB]">
          {renderView()}
        </div>
      </main>
    </div>
  );
};

export default App;

