import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, ShoppingCart, Trash2, UserPlus, CreditCard, Banknote, UserCheck } from 'lucide-react';
import { PRODUCTS, CATEGORIES } from '../constants';
import { Product, CartItem, Ingredient, Variant, Customer } from '../types';
import { calculerTotaux, formatPrix } from '../utils';

interface POSProps {
  ingredients: Ingredient[];
  customers: Customer[];
  onAddOrder: (items: CartItem[], total: number, paymentMethod: 'CASH' | 'CARD', customerId?: string) => void;
}

const POS: React.FC<POSProps> = ({ ingredients, customers, onAddOrder }) => {
  const [activeCategoryId, setActiveCategoryId] = useState<string>(CATEGORIES[0].id);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>();
  const [showCustomerSearch, setShowCustomerSearch] = useState(false);

  const selectedCustomer = customers.find(c => c.id === selectedCustomerId);

  const isProduitDisponible = (produit: Product) => {
    if (!produit.recipe || produit.recipe.length === 0) return true;
    return produit.recipe.every(item => {
      const ingredient = ingredients.find(i => i.id === item.ingredientId);
      return ingredient && ingredient.currentStock >= item.quantity;
    });
  };

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(p => 
      (activeCategoryId === 'all' || p.categoryId === activeCategoryId) &&
      p.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [activeCategoryId, searchQuery]);

  const addToCart = (product: Product, variants: Variant[] = []) => {
    const prixVariantes = variants.reduce((sum, v) => sum + v.priceExtra, 0);
    const unitPrice = product.price + prixVariantes;
    const newItem: CartItem = {
      id: crypto.randomUUID(),
      productId: product.id,
      product,
      quantity: 1,
      selectedVariants: variants,
      unitPrice,
      totalPrice: unitPrice,
    };
    setCart(prev => [...prev, newItem]);
    setSelectedProduct(null);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty, totalPrice: item.unitPrice * newQty };
      }
      return item;
    }));
  };

  const totals = useMemo(() => calculerTotaux(cart), [cart]);

  const handleCheckout = (method: 'CASH' | 'CARD') => {
    onAddOrder(cart, totals.totalTTC, method, selectedCustomerId);
    setCart([]);
    setSelectedCustomerId(undefined);
  };

  return (
    <div className="flex h-[calc(100vh-64px)] overflow-hidden">
      <div className="flex-1 p-6 overflow-y-auto space-y-6">
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
          <div className="relative w-full md:w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher produit..."
