import React, { useMemo } from 'react';
import { TrendingUp, ShoppingBag, Users, Wallet, AlertCircle, ArrowRight } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Order, Ingredient } from '../types';
import { formatPrix } from '../utils';

interface DashboardProps {
  orders: Order[];
  ingredients: Ingredient[];
  expenses: any[];
  onViewChange: (view: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ orders, ingredients, expenses, onViewChange }) => {
  // Calculs dynamiques
  const stats = useMemo(() => {
    const totalSales = orders.reduce((acc, o) => acc + o.total, 0);
    const orderCount = orders.length;
    const avgBasket = orderCount > 0 ? totalSales / orderCount : 0;
    const totalExpenses = expenses.reduce((acc, e) => acc + e.amount, 0);

    // Alertes stock
    const alerts = ingredients.filter(i => i.currentStock <= i.minStock);

    // Données pour le graphique (simplifié : ventes par heure)
    const hourlyData = Array.from({ length: 8 }, (_, i) => {
      const hour = 11 + i;
      return {
        name: `${hour}h`,
        sales: orders.filter(o => new Date(o.timestamp).getHours() === hour)
                     .reduce((acc, o) => acc + o.total, 0)
      };
    });

    return { totalSales, orderCount, avgBasket, totalExpenses, alerts, hourlyData };
  }, [orders, ingredients, expenses]);

  return (
    <div className="p-6 space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black">Molly's Truck Dashboard 👋</h1>
          <p className="text-gray-500 font-medium">Analyse de performance en temps réel</p>
