          <div className="bg-gradient-to-br from-orange-500 to-orange-600 p-8 rounded-3xl text-white shadow-xl shadow-orange-100">
            <h3 className="font-black text-xl mb-2">Objectif Molly's Truck</h3>
            <p className="text-orange-100 text-sm mb-6 font-medium">Progression du jour basée sur votre cible de 1500€.</p>
            <div className="w-full bg-white/20 rounded-full h-3 mb-3">
              <div 
                className="bg-white h-full rounded-full transition-all duration-1000" 
                style={{ width: `${Math.min((stats.totalSales / 1500) * 100, 100)}%` }}
              ></div>
            </div>
            <div className="flex justify-between items-end">
               <span className="text-2xl font-black">{Math.round((stats.totalSales / 1500) * 100)}%</span>
               <span className="text-xs font-bold opacity-80 uppercase tracking-tighter">{formatPrix(stats.totalSales)} / 1 500€</span>
            </div>
          </div>
        </div>
