import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import KDS from './components/KDS';
import Inventory from './components/Inventory';
import CRM from './components/CRM';
import ExpensesView from './components/ExpensesView';
import { Order, CartItem, OrderStatus, Ingredient, Customer } from './types';
import { MOCK_ORDERS, INGREDIENTS, MOCK_CUSTOMERS } from './constants';
import { Bell } from 'lucide-react';
import { formatPrix } from './utils';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('dashboard');
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('molls_orders');
    return saved ? JSON.parse(saved) : MOCK_ORDERS;
  });
  const [ingredients, setIngredients] = useState<Ingredient[]>(() => {
    const saved = localStorage.getItem('molls_ingredients');
    return saved ? JSON.parse(saved) : INGREDIENTS;
  });
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('molls_customers');
    return saved ? JSON.parse(saved) : MOCK_CUSTOMERS;
  });
  const [expenses, setExpenses] = useState<any[]>(() => {
    const saved = localStorage.getItem('molls_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  // Persistance automatique
  useEffect(() => {
    localStorage.setItem('molls_orders', JSON.stringify(orders));
    localStorage.setItem('molls_ingredients', JSON.stringify(ingredients));
    localStorage.setItem('molls_customers', JSON.stringify(customers));
    localStorage.setItem('molls_expenses', JSON.stringify(expenses));
  }, [orders, ingredients, customers, expenses]);

  const processStockReduction = (items: CartItem[]) => {
    setIngredients(prev => {
      const next = [...prev];
      items.forEach(item => {
        const product = item.product;
        if (product.recipe) {
          product.recipe.forEach(recipeItem => {
            const ingIdx = next.findIndex(i => i.id === recipeItem.ingredientId);
            if (ingIdx !== -1) {
              next[ingIdx] = {
                ...next[ingIdx],
                currentStock: Number((next[ingIdx].currentStock - (recipeItem.quantity * item.quantity)).toFixed(2))
              };
            }
          });
        }
      });
      return next;
    });
  };

  const handleAddOrder = (items: CartItem[], total: number, paymentMethod: 'CASH' | 'CARD', customerId?: string) => {
    const newOrder: Order = {
      id: `o-${Date.now()}`,
      orderNumber: `MT-${orders.length + 101}`,
      timestamp: Date.now(),
      items,
      total,
      status: 'PENDING',
      paymentMethod,
      customerId
    };

    setOrders(prev => [newOrder, ...prev]);
    processStockReduction(items);

    if (customerId) {
      setCustomers(prev => prev.map(c => 
        c.id === customerId ? { ...c, loyaltyPoints: c.loyaltyPoints + Math.floor(total), lastVisit: Date.now() } : c
      ));
    }

    setCurrentView('kds');
  };

  const updateOrderStatus = (orderId: string, newStatus: OrderStatus) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
  };

  const handleAddExpense = (expense: any) => {
    setExpenses(prev => [{ ...expense, id: Date.now().toString() }, ...prev]);
  };

  const handleAddCustomer = (c: Omit<Customer, 'id' | 'loyaltyPoints' | 'lastVisit'>) => {
    const newCust: Customer = {
      ...c,
      id: `c-${Date.now()}`,
      loyaltyPoints: 0,
      lastVisit: undefined
    };
    setCustomers(prev => [...prev, newCust]);
  };

  const handleAddIngredient = (i: Omit<Ingredient, 'id'>) => {
    const newIng: Ingredient = {
      ...i,
      id: `ing-${Date.now()}`
    };
    setIngredients(prev => [...prev, newIng]);
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard orders={orders} ingredients={ingredients} expenses={expenses} onViewChange={setCurrentView} />;
      case 'pos': return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} />;
      case 'kds': return <KDS orders={orders} onStatusChange={updateOrderStatus} />;
      case 'inventory': return <Inventory ingredients={ingredients} onAddIngredient={handleAddIngredient} />;
      case 'customers': return <CRM customers={customers} orders={orders} onAddCustomer={handleAddCustomer} />;
      case 'expenses': return <ExpensesView expenses={expenses} onAdd={handleAddExpense} />;
      case 'orders':
        return (
          <div className="p-6 animate-in fade-in">
            <h2 className="text-2xl font-black mb-6">Historique des commandes</h2>
            <div className="bg-white rounded-3xl border border-gray-100 overflow-hidden shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-gray-50/50 font-black text-gray-400 uppercase text-[10px] tracking-widest border-b border-gray-50">
                  <tr>
                    <th className="px-6 py-4">Commande</th>
                    <th className="px-6 py-4">Heure</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Paiement</th>
                    <th className="px-6 py-4 text-right">Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {orders.map(o => (
                    <tr key={o.id} className="hover:bg-gray-50/50 transition-colors">
                      <td className="px-6 py-4 font-black text-gray-800">#{o.orderNumber}</td>
                      <td className="px-6 py-4 text-gray-500 text-sm font-medium">{new Date(o.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2.5 py-1 rounded-full text-[10px] font-black uppercase border ${
                          o.status === 'SERVED' ? 'bg-green-50 text-green-600 border-green-100' : 'bg-orange-50 text-orange-600 border-orange-100'
                        }`}>{o.status}</span>
                      </td>
                      <td className="px-6 py-4 text-xs font-bold text-gray-400 italic">{o.paymentMethod || 'N/A'}</td>
                      <td className="px-6 py-4 text-right font-black text-gray-900">{formatPrix(o.total)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );
      default: return <Dashboard orders={orders} ingredients={ingredients} expenses={expenses} onViewChange={setCurrentView} />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900 overflow-hidden">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} />
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="h-16 bg-white border-b border-gray-100 px-6 flex items-center justify-between sticky top-0 z-20">
          <div className="flex items-center gap-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">
            <span className="hidden sm:inline">Emplacement : Marché des Halles</span>
            <div className="flex items-center gap-1.5">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              <span className="text-green-500 font-black">Service Molly's Truck Ouvert</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button className="relative p-2 text-gray-400 hover:text-orange-600 transition-colors">
              <Bell size={20} />
            </button>
            <div className="h-8 w-px bg-gray-100"></div>
            <div className="w-8 h-8 rounded-full bg-orange-600 text-white flex items-center justify-center font-black text-xs shadow-lg shadow-orange-100">JD</div>
          </div>
        </header>
        <div className="flex-1 overflow-y-auto bg-[#FBFBFB]">
          {renderView()}
        </div>
      </main>
    </div>
  );
};

