import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, ShoppingCart, Trash2, UserPlus, CreditCard, Banknote, UserCheck, UtensilsCrossed, Package2, Ticket } from 'lucide-react';
import { PRODUCTS, CATEGORIES } from '../constants';
import { Product, CartItem, Ingredient, Variant, Customer, ServiceMode, PaymentMethod } from '../types';
import { calculerTotaux, formatPrix } from '../utils';

interface POSProps {
  ingredients: Ingredient[];
  customers: Customer[];
  onAddOrder: (items: CartItem[], total: number, paymentMethod: PaymentMethod, serviceMode: ServiceMode, customerId?: string) => void;
}

const POS: React.FC<POSProps> = ({ ingredients, customers, onAddOrder }) => {
  const [activeCategoryId, setActiveCategoryId] = useState<string>('all');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>();
  const [showCustomerSearch, setShowCustomerSearch] = useState(false);
  const [serviceMode, setServiceMode] = useState<ServiceMode>('TAKEAWAY');

  const selectedCustomer = customers.find(c => c.id === selectedCustomerId);

  const isProduitDisponible = (produit: Product) => {
    if (!produit.recipe || produit.recipe.length === 0) return true;
    return produit.recipe.every(item => {
      const ingredient = ingredients.find(i => i.id === item.ingredientId);
      return ingredient && ingredient.currentStock >= item.quantity;
    });
  };

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(p => 
      (activeCategoryId === 'all' || p.categoryId === activeCategoryId) &&
      p.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [activeCategoryId, searchQuery]);

  const addToCart = (product: Product, variants: Variant[] = []) => {
    const prixVariantes = variants.reduce((sum, v) => sum + v.priceExtra, 0);
    const unitPrice = product.price + prixVariantes;
    const newItem: CartItem = {
      id: crypto.randomUUID(),
      productId: product.id,
      product,
      quantity: 1,
      selectedVariants: variants,
      unitPrice,
      totalPrice: unitPrice,
    };
    setCart(prev => [...prev, newItem]);
    setSelectedProduct(null);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty, totalPrice: item.unitPrice * newQty };
      }
      return item;
    }));
  };

  const totals = useMemo(() => calculerTotaux(cart), [cart]);

  const handleCheckout = (method: PaymentMethod) => {
    onAddOrder(cart, totals.totalTTC, method, serviceMode, selectedCustomerId);
    setCart([]);
    setSelectedCustomerId(undefined);
  };

  return (
    <div className="flex h-[calc(100vh-64px)] overflow-hidden bg-[#F1F3F6]">
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Top Header Filter Pills */}
        <div className="bg-white p-4 border-b border-gray-200 shadow-sm flex items-center gap-3 overflow-x-auto scrollbar-hide shrink-0">
          <button 
            onClick={() => setActiveCategoryId('all')}
            className={`px-8 py-2.5 rounded-full text-sm font-black transition-all ${activeCategoryId === 'all' ? 'bg-[#222] text-white' : 'bg-white text-gray-400 border border-gray-100 hover:bg-gray-50'}`}
          >
            Tout
          </button>
          {CATEGORIES.map(cat => (
            <button 
              key={cat.id} 
              onClick={() => setActiveCategoryId(cat.id)}
              className={`px-8 py-2.5 rounded-full text-sm font-black transition-all ${activeCategoryId === cat.id ? 'bg-[#222] text-white' : 'bg-white text-gray-400 border border-gray-100 hover:bg-gray-50'}`}
            >
              {cat.name}
            </button>
          ))}
        </div>

        {/* Search & Grid */}
        <div className="flex-1 p-6 overflow-y-auto space-y-6">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
            <input 
              type="text" 
              placeholder="Rechercher un produit..."
              className="w-full pl-12 pr-4 py-4 bg-white border border-gray-200 rounded-2xl focus:ring-2 focus:ring-[#9d174d] outline-none shadow-sm font-medium"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredProducts.map(product => {
              const disponible = isProduitDisponible(product);
              return (
                <button 
                  key={product.id}
                  disabled={!disponible}
                  onClick={() => product.variants ? setSelectedProduct(product) : addToCart(product)}
                  className={`bg-white rounded-3xl border border-gray-100 shadow-sm transition-all text-left flex flex-col h-full relative overflow-hidden group ${disponible ? 'hover:shadow-xl hover:-translate-y-1 active:scale-95' : 'opacity-60 grayscale cursor-not-allowed'}`}
                >
                  <div className="relative aspect-[4/3] overflow-hidden bg-gray-100">
                    <img src={product.imageUrl} alt={product.name} className="w-full h-full object-cover transition duration-500 group-hover:scale-110" />
                    <div className="absolute bottom-3 right-3 bg-white/95 backdrop-blur-md px-3 py-1.5 rounded-xl font-black text-sm text-gray-800 shadow-lg">
                      {formatPrix(product.price)}
                    </div>
                    {product.variants && (
                      <div className="absolute top-3 right-3 bg-[#9d174d] text-white px-2 py-0.5 rounded-lg font-black text-[9px] uppercase tracking-widest shadow-lg">
                        Options
                      </div>
                    )}
                  </div>
                  <div className="p-4 flex-1 flex flex-col">
                    <h3 className="font-black text-gray-800 text-base leading-tight group-hover:text-[#9d174d] transition-colors">{product.name}</h3>
                    <p className="text-[10px] font-bold text-gray-400 uppercase mt-1">
                      {CATEGORIES.find(c => c.id === product.categoryId)?.name}
                    </p>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      </div>

      {/* Cart Sidebar Inspired by Image */}
      <div className="w-[420px] bg-white border-l border-gray-200 flex flex-col shadow-2xl z-20">
        <div className="p-6 space-y-4">
          <button 
            onClick={() => setShowCustomerSearch(true)}
            className="w-full flex items-center justify-center gap-2 p-4 bg-gray-50 border-2 border-dashed border-gray-200 rounded-2xl text-gray-500 hover:bg-gray-100 hover:border-gray-300 transition-all group"
          >
            {selectedCustomer ? (
              <div className="flex items-center gap-2 text-[#9d174d]">
                <UserCheck size={20} />
                <span className="font-black">{selectedCustomer.name}</span>
              </div>
            ) : (
              <div className="flex items-center gap-2">
                <UserPlus size={20} className="group-hover:scale-110 transition-transform" />
                <span className="font-bold">Identifier Client</span>
              </div>
            )}
          </button>

          <div className="flex bg-gray-50 p-1 rounded-2xl border border-gray-100">
            <button 
              onClick={() => setServiceMode('TAKEAWAY')}
              className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-xs font-black transition-all ${serviceMode === 'TAKEAWAY' ? 'bg-white text-[#9d174d] shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
            >
              <Truck size={16} /> À EMPORTER
            </button>
            <button 
              onClick={() => setServiceMode('DINE_IN')}
              className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-xs font-black transition-all ${serviceMode === 'DINE_IN' ? 'bg-white text-[#9d174d] shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
            >
              <UtensilsCrossed size={16} /> SUR PLACE
            </button>
          </div>
        </div>

        <div className="px-6 flex items-center gap-2 mb-2">
           <h2 className="font-black text-lg">Panier</h2>
           <span className="bg-[#9d174d] text-white text-[10px] font-black w-5 h-5 flex items-center justify-center rounded-full">{cart.length}</span>
        </div>

        <div className="flex-1 overflow-y-auto px-6 space-y-4 py-2">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-300 gap-4 opacity-50 grayscale">
              <ShoppingCart size={64} strokeWidth={1} />
              <p className="font-black text-sm uppercase tracking-widest text-center">Panier vide<br/><span className="text-[10px] font-bold">Sélectionnez des produits</span></p>
            </div>
          ) : cart.map(item => (
            <div key={item.id} className="flex flex-col bg-gray-50/50 p-4 rounded-3xl border border-gray-100 group animate-in slide-in-from-right-4 duration-200">
              <div className="flex items-center justify-between">
                <div className="flex-1">
                  <p className="font-black text-sm text-gray-800 leading-tight">{item.product.name}</p>
                  {item.selectedVariants.length > 0 && (
                    <p className="text-[10px] text-gray-500 font-bold mt-1">
                      {item.selectedVariants.map(v => v.name).join(', ')}
                    </p>
                  )}
                  <p className="text-xs font-black text-[#9d174d] mt-2">{formatPrix(item.totalPrice)}</p>
                </div>
                <div className="flex items-center gap-2 bg-white rounded-2xl p-1 shadow-sm border border-gray-100">
                  <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-gray-50 rounded-xl transition-colors"><Minus size={14} /></button>
                  <span className="w-6 text-center text-sm font-black">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-gray-50 rounded-xl transition-colors"><Plus size={14} /></button>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="p-6 bg-white border-t border-gray-100 space-y-6">
          <div className="space-y-2">
            <div className="flex justify-between text-xs font-bold text-gray-400">
              <span>Total HT</span>
              <span>{formatPrix(totals.totalHT)}</span>
            </div>
            <div className="flex justify-between text-xs font-bold text-gray-400">
              <span>TVA</span>
              <span>{formatPrix(totals.totalTVA)}</span>
            </div>
            <div className="h-px bg-gray-50 my-2"></div>
            <div className="flex justify-between items-end">
              <span className="font-black text-xl">Total TTC</span>
              <span className="text-3xl font-black text-[#9d174d] tracking-tighter">{formatPrix(totals.totalTTC)}</span>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-3">
            <button 
              disabled={cart.length === 0} 
              onClick={() => handleCheckout('CARD')}
              className="flex flex-col items-center justify-center gap-2 bg-gray-500 text-white py-4 rounded-2xl shadow-lg hover:bg-gray-600 transition-all disabled:opacity-50"
            >
              <CreditCard size={24} />
              <span className="text-[9px] font-black uppercase">CARTE</span>
            </button>
            <button 
              disabled={cart.length === 0} 
              onClick={() => handleCheckout('CASH')}
              className="flex flex-col items-center justify-center gap-2 bg-[#A3D98E] text-white py-4 rounded-2xl shadow-lg hover:bg-[#8EC878] transition-all disabled:opacity-50"
            >
              <Banknote size={24} />
              <span className="text-[9px] font-black uppercase">ESPÈCES</span>
            </button>
            <button 
              disabled={cart.length === 0} 
              onClick={() => handleCheckout('TR')}
              className="flex flex-col items-center justify-center gap-2 bg-[#F6B387] text-white py-4 rounded-2xl shadow-lg hover:bg-[#E29D70] transition-all disabled:opacity-50"
            >
              <Ticket size={24} />
              <span className="text-[9px] font-black uppercase">TR</span>
            </button>
          </div>
        </div>
      </div>

      {showCustomerSearch && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] w-full max-w-md p-8 animate-in zoom-in-95">
            <h2 className="text-2xl font-black mb-6">Sélectionner un client</h2>
            <div className="space-y-3 max-h-96 overflow-y-auto pr-2">
              {customers.map(c => (
                <button 
                  key={c.id} 
                  onClick={() => { setSelectedCustomerId(c.id); setShowCustomerSearch(false); }}
                  className="w-full p-5 flex justify-between items-center bg-gray-50 rounded-2xl hover:bg-[#9d174d]/5 border border-transparent hover:border-[#9d174d]/20 transition-all"
                >
                  <div className="text-left">
                    <p className="font-black text-gray-800">{c.name}</p>
                    <p className="text-xs text-gray-400 font-bold">{c.phone}</p>
                  </div>
                  <span className="bg-[#9d174d] text-white text-[10px] font-black px-2 py-1 rounded-lg">{c.loyaltyPoints} PTS</span>
                </button>
              ))}
            </div>
            <button onClick={() => setShowCustomerSearch(false)} className="w-full mt-8 py-3 text-sm font-black text-gray-400 uppercase tracking-widest">Annuler</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import KDS from './components/KDS';
import Inventory from './components/Inventory';
import CRM from './components/CRM';
import ExpensesView from './components/ExpensesView';
import { Order, CartItem, OrderStatus, Ingredient, Customer, PaymentMethod, ServiceMode } from './types';
import { MOCK_ORDERS, INGREDIENTS, MOCK_CUSTOMERS } from './constants';
import { Bell, Search, User } from 'lucide-react';
import { formatPrix } from './utils';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('pos');
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('molls_orders');
    return saved ? JSON.parse(saved) : MOCK_ORDERS;
  });
  const [ingredients, setIngredients] = useState<Ingredient[]>(() => {
    const saved = localStorage.getItem('molls_ingredients');
    return saved ? JSON.parse(saved) : INGREDIENTS;
  });
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('molls_customers');
    return saved ? JSON.parse(saved) : MOCK_CUSTOMERS;
  });
  const [expenses, setExpenses] = useState<any[]>(() => {
    const saved = localStorage.getItem('molls_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('molls_orders', JSON.stringify(orders));
    localStorage.setItem('molls_ingredients', JSON.stringify(ingredients));
    localStorage.setItem('molls_customers', JSON.stringify(customers));
    localStorage.setItem('molls_expenses', JSON.stringify(expenses));
  }, [orders, ingredients, customers, expenses]);

  const processStockReduction = (items: CartItem[]) => {
    setIngredients(prev => {
      const next = [...prev];
      items.forEach(item => {
        const product = item.product;
        if (product.recipe) {
          product.recipe.forEach(recipeItem => {
            const ingIdx = next.findIndex(i => i.id === recipeItem.ingredientId);
            if (ingIdx !== -1) {
              next[ingIdx] = {
                ...next[ingIdx],
                currentStock: Number((next[ingIdx].currentStock - (recipeItem.quantity * item.quantity)).toFixed(2))
              };
            }
          });
        }
      });
      return next;
    });
  };

  const handleAddOrder = (items: CartItem[], total: number, paymentMethod: PaymentMethod, serviceMode: ServiceMode, customerId?: string) => {
    const newOrder: Order = {
      id: `o-${Date.now()}`,
      orderNumber: `${orders.length + 101}`,
      timestamp: Date.now(),
      items,
      total,
      status: 'PENDING',
      paymentMethod,
      serviceMode,
      customerId
    };

    setOrders(prev => [newOrder, ...prev]);
    processStockReduction(items);

    if (customerId) {
      setCustomers(prev => prev.map(c => 
        c.id === customerId ? { ...c, loyaltyPoints: c.loyaltyPoints + Math.floor(total), lastVisit: Date.now() } : c
      ));
    }

    setCurrentView('kds');
  };

  const updateOrderStatus = (orderId: string, newStatus: OrderStatus) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
  };

  const handleAddExpense = (expense: any) => {
    setExpenses(prev => [{ ...expense, id: Date.now().toString() }, ...prev]);
  };

  const handleAddCustomer = (c: Omit<Customer, 'id' | 'loyaltyPoints' | 'lastVisit'>) => {
    const newCust: Customer = { ...c, id: `c-${Date.now()}`, loyaltyPoints: 0, lastVisit: undefined };
    setCustomers(prev => [...prev, newCust]);
  };

  const handleAddIngredient = (i: Omit<Ingredient, 'id'>) => {
    const newIng: Ingredient = { ...i, id: `ing-${Date.now()}` };
    setIngredients(prev => [...prev, newIng]);
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard orders={orders} ingredients={ingredients} expenses={expenses} onViewChange={setCurrentView} />;
      case 'pos': return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} />;
      case 'kds': return <KDS orders={orders} onStatusChange={updateOrderStatus} />;
      case 'inventory': return <Inventory ingredients={ingredients} onAddIngredient={handleAddIngredient} />;
      case 'customers': return <CRM customers={customers} orders={orders} onAddCustomer={handleAddCustomer} />;
      case 'expenses': return <ExpensesView expenses={expenses} onAdd={handleAddExpense} />;
      case 'orders':
        return (
          <div className="p-8 animate-in fade-in">
            <h2 className="text-3xl font-black mb-8 text-gray-800">Journal des ventes</h2>
            <div className="bg-white rounded-[2rem] border border-gray-100 overflow-hidden shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-gray-50/50 font-black text-gray-400 uppercase text-[10px] tracking-widest border-b border-gray-50">
                  <tr>
                    <th className="px-8 py-6">Ticket</th>
                    <th className="px-8 py-6">Consommation</th>
                    <th className="px-8 py-6">Mode</th>
                    <th className="px-8 py-6">Status</th>
                    <th className="px-8 py-6 text-right">Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {orders.map(o => (
                    <tr key={o.id} className="hover:bg-gray-50/50 transition-colors group">
                      <td className="px-8 py-6">
                        <span className="font-black text-gray-800">#{o.orderNumber}</span>
                        <p className="text-[10px] font-bold text-gray-400 uppercase">{new Date(o.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                      </td>
                      <td className="px-8 py-6">
                        <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase border ${o.serviceMode === 'DINE_IN' ? 'bg-purple-50 text-purple-600 border-purple-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                          {o.serviceMode === 'DINE_IN' ? 'Sur Place' : 'À Emporter'}
                        </span>
                      </td>
                      <td className="px-8 py-6 font-bold text-gray-400 text-xs italic">{o.paymentMethod || 'N/A'}</td>
                      <td className="px-8 py-6">
                        <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase ${o.status === 'SERVED' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>{o.status}</span>
                      </td>
                      <td className="px-8 py-6 text-right font-black text-gray-900 text-lg">{formatPrix(o.total)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );
      default: return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900 overflow-hidden font-['Inter']">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} />
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="h-20 bg-white border-b border-gray-100 px-8 flex items-center justify-between sticky top-0 z-20 shrink-0">
          <div className="flex items-center gap-6">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Poste de travail</span>
              <span className="font-black text-gray-800">Caisse Centrale 01</span>
            </div>
            <div className="h-8 w-px bg-gray-100"></div>
            <div className="flex items-center gap-2">
              <span className="w-2.5 h-2.5 rounded-full bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.5)] animate-pulse"></span>
              <span className="text-xs font-black text-green-600 uppercase tracking-tight">Shift Molly's Ouvert</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="relative group">
               <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-300 group-hover:text-[#9d174d] transition-colors" size={18} />
               <input type="text" placeholder="Recherche rapide..." className="bg-gray-50 border-none rounded-2xl pl-10 pr-4 py-2.5 text-sm font-medium w-64 focus:ring-2 focus:ring-[#9d174d] outline-none transition-all" />
            </div>
            <button className="p-3 bg-gray-50 rounded-2xl text-gray-400 hover:text-[#9d174d] transition-all relative">
              <Bell size={20} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-[#9d174d] rounded-full border-2 border-white"></span>
            </button>
          </div>
        </header>
        <div className="flex-1 overflow-y-auto bg-[#F1F3F6]">
          {renderView()}
        </div>
      </main>
    </div>
  );
};

