import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, ShoppingCart, CreditCard, Banknote, UserCheck, UtensilsCrossed, Ticket, Truck, Printer, Wifi, WifiOff } from 'lucide-react';
import { PRODUCTS, CATEGORIES } from '../constants';
import { Product, CartItem, Ingredient, Customer, ServiceMode, PaymentMethod } from '../types';
import { calculerTotaux, formatPrix } from '../utils';

interface POSProps {
  ingredients: Ingredient[];
  customers: Customer[];
  onAddOrder: (items: CartItem[], total: number, paymentMethod: PaymentMethod, serviceMode: ServiceMode, customerId?: string) => void;
}

const POS: React.FC<POSProps> = ({ ingredients, customers, onAddOrder }) => {
  const [activeCategoryId, setActiveCategoryId] = useState<string>('all');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>();
  const [serviceMode, setServiceMode] = useState<ServiceMode>('TAKEAWAY');
  const [isPrinting, setIsPrinting] = useState(false);
  const [isTpeConnected, setIsTpeConnected] = useState(true);

  const totals = useMemo(() => calculerTotaux(cart), [cart]);

  const handlePrint = () => {
    setIsPrinting(true);
    setTimeout(() => setIsPrinting(false), 2000);
  };

  const handleCheckout = (method: PaymentMethod) => {
    if (cart.length === 0) return;
    onAddOrder(cart, totals.totalTTC, method, serviceMode, selectedCustomerId);
    setCart([]);
    setSelectedCustomerId(undefined);
    handlePrint();
  };

  const addToCart = (product: Product) => {
    const existing = cart.find(item => item.productId === product.id);
    if (existing) {
      setCart(prev => prev.map(item => item.productId === product.id ? {...item, quantity: item.quantity + 1, totalPrice: (item.quantity + 1) * item.unitPrice} : item));
    } else {
      const newItem: CartItem = {
        id: crypto.randomUUID(),
        productId: product.id,
        product,
        quantity: 1,
        unitPrice: product.price,
        totalPrice: product.price,
      };
      setCart(prev => [...prev, newItem]);
    }
  };

  return (
    <div className="flex h-full overflow-hidden bg-[#F1F3F6]">
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Header Status */}
        <div className="bg-white p-4 border-b border-gray-200 flex justify-between items-center shrink-0">
          <div className="flex gap-2">
            {CATEGORIES.map(cat => (
              <button 
                key={cat.id} 
                onClick={() => setActiveCategoryId(cat.id)}
                className={`px-6 py-2 rounded-full text-[10px] font-black tracking-widest transition-all uppercase ${activeCategoryId === cat.id ? 'bg-[#9d174d] text-white shadow-lg' : 'bg-gray-100 text-gray-400 hover:bg-gray-200'}`}
              >
                {cat.name}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-4">
            <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase ${isTpeConnected ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
              {isTpeConnected ? <Wifi size={12} /> : <WifiOff size={12} />} TPE : {isTpeConnected ? 'Connecté' : 'Erreur'}
            </div>
          </div>
        </div>

        <div className="flex-1 p-8 overflow-y-auto grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6 content-start">
          {PRODUCTS.filter(p => activeCategoryId === 'all' || p.categoryId === activeCategoryId).map(product => (
            <button 
              key={product.id}
              onClick={() => addToCart(product)}
              className="bg-white rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all text-left overflow-hidden group active:scale-95"
            >
              <div className="aspect-square bg-gray-100 relative">
                <img src={product.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                <div className="absolute bottom-4 right-4 bg-white/95 backdrop-blur px-3 py-1 rounded-xl font-black text-sm shadow-xl">
                  {formatPrix(product.price)}
                </div>
              </div>
              <div className="p-5">
                <h3 className="font-black text-gray-800 leading-tight">{product.name}</h3>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="w-96 bg-white border-l border-gray-200 flex flex-col shadow-2xl relative z-20">
        <div className="p-6 border-b border-gray-100 space-y-4">
          <div className="flex bg-gray-100 p-1.5 rounded-[1.5rem]">
            <button onClick={() => setServiceMode('TAKEAWAY')} className={`flex-1 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${serviceMode === 'TAKEAWAY' ? 'bg-white text-[#9d174d] shadow-sm' : 'text-gray-400'}`}>
              <Truck size={14} className="inline mr-2" /> Emporter
            </button>
            <button onClick={() => setServiceMode('DINE_IN')} className={`flex-1 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${serviceMode === 'DINE_IN' ? 'bg-white text-[#9d174d] shadow-sm' : 'text-gray-400'}`}>
              <UtensilsCrossed size={14} className="inline mr-2" /> Sur Place
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4">
          {cart.map(item => (
            <div key={item.id} className="flex justify-between items-center animate-in slide-in-from-right-4">
              <div className="flex items-center gap-3">
                <span className="w-8 h-8 flex items-center justify-center bg-gray-100 rounded-xl font-black text-sm">{item.quantity}</span>
                <span className="font-bold text-gray-800 text-sm">{item.product.name}</span>
              </div>
              <span className="font-black text-sm">{formatPrix(item.totalPrice)}</span>
            </div>
          ))}
        </div>

        <div className="p-8 bg-gray-50 border-t border-gray-200 rounded-t-[3rem] space-y-6">
          <div className="flex justify-between items-end">
            <span className="font-black text-gray-400 text-xs uppercase tracking-widest">A payer</span>
            <span className="text-4xl font-black text-[#9d174d] tracking-tighter">{formatPrix(totals.totalTTC)}</span>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => handleCheckout('CARD')} disabled={cart.length === 0} className="bg-gray-900 text-white p-5 rounded-3xl font-black text-[10px] uppercase tracking-widest flex flex-col items-center gap-2 hover:bg-black transition-all active:scale-95 disabled:opacity-50">
              <CreditCard size={24} /> Carte Bancaire
