            <button onClick={() => handleCheckout('CASH')} disabled={cart.length === 0} className="bg-[#9d174d] text-white p-5 rounded-3xl font-black text-[10px] uppercase tracking-widest flex flex-col items-center gap-2 hover:bg-[#831441] transition-all active:scale-95 disabled:opacity-50">
              <Banknote size={24} /> Espèces
