        <div className="flex items-center gap-2">
          <button 
            onClick={() => onViewChange('pos')}
            className="bg-[#b3247e] text-white px-6 py-2.5 rounded-xl font-bold hover:bg-[#a11d6e] transition shadow-lg shadow-pink-100 flex items-center gap-2"
          >
            <ShoppingBag size={18} /> Prendre une commande
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Chiffre d\'Affaires', value: formatPrix(stats.totalSales), icon: Wallet, color: 'text-[#54bb24]', bg: 'bg-green-50' },
          { label: 'Commandes', value: stats.orderCount, icon: ShoppingBag, color: 'text-[#b3247e]', bg: 'bg-pink-50' },
          { label: 'Panier Moyen', value: formatPrix(stats.avgBasket), icon: TrendingUp, color: 'text-purple-600', bg: 'bg-purple-50' },
          { label: 'Dépenses', value: formatPrix(stats.totalExpenses), icon: Users, color: 'text-red-600', bg: 'bg-red-50' },
        ].map((kpi, idx) => (
          <div key={idx} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between mb-4">
              <div className={`${kpi.bg} p-3 rounded-2xl`}>
                <kpi.icon className={kpi.color} size={24} />
              </div>
            </div>
            <p className="text-xs font-black text-gray-400 uppercase tracking-widest">{kpi.label}</p>
            <h3 className="text-2xl font-black mt-1 text-gray-800">{kpi.value}</h3>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="font-black text-lg text-gray-800 uppercase tracking-tight">Activité Ventes (Aujourd'hui)</h3>
          </div>
          <div className="h-72 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={stats.hourlyData}>
                <defs>
                  <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#b3247e" stopOpacity={0.2}/>
                    <stop offset="95%" stopColor="#b3247e" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 600}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)', fontWeight: 'bold' }}
                />
                <Area type="monotone" dataKey="sales" stroke="#b3247e" strokeWidth={4} fillOpacity={1} fill="url(#colorSales)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <h3 className="font-black text-lg mb-6 flex items-center gap-2 text-gray-800">
              <AlertCircle size={20} className="text-[#b3247e]" /> 
              ALERTES STOCKS
            </h3>
            <div className="space-y-3">
              {stats.alerts.length > 0 ? stats.alerts.map((alert, i) => (
                <div key={i} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl border border-transparent hover:border-red-100 transition-all">
