import React from 'react';
import { Clock, CheckCircle2, AlertCircle } from 'lucide-react';
import { Order, OrderStatus } from '../types';
import { PRODUCTS } from '../constants';

interface KDSProps {
  orders: Order[];
  onStatusChange: (orderId: string, newStatus: OrderStatus) => void;
}

const KDS: React.FC<KDSProps> = ({ orders, onStatusChange }) => {
  const pendingOrders = orders.filter(o => o.status === 'PENDING' || o.status === 'PREPARING');
  const readyOrders = orders.filter(o => o.status === 'READY');

  const Ticket: React.FC<{ order: Order }> = ({ order }) => {
    const elapsed = Math.floor((Date.now() - order.timestamp) / 60000);
    const isLate = elapsed > 15;

    return (
      <div className={`bg-white rounded-2xl shadow-sm border-l-8 ${
        order.status === 'PREPARING' ? 'border-[#b3247e]' : 'border-[#54bb24]'
      } overflow-hidden`}>
        <div className="p-4 border-b border-gray-50 flex justify-between items-center">
          <div>
            <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">#{order.orderNumber}</span>
            <h4 className="font-black text-lg">Commande #{order.orderNumber.split('-')[1]}</h4>
          </div>
          <div className={`flex items-center gap-1 text-sm font-bold ${isLate ? 'text-red-500' : 'text-gray-500'}`}>
            <Clock size={16} /> {elapsed}m
          </div>
        </div>

        <div className="p-4 space-y-3">
          {order.items.map((item, idx) => {
            const product = PRODUCTS.find(p => p.id === item.productId);
            return (
              <div key={idx} className="flex justify-between items-start">
                <div className="flex gap-3">
                  <span className="w-6 h-6 flex items-center justify-center bg-gray-100 rounded text-sm font-bold">{item.quantity}</span>
                  <span className="font-bold text-gray-800">{product?.name}</span>
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-3 bg-gray-50">
          {order.status === 'PENDING' ? (
            <button 
              onClick={() => onStatusChange(order.id, 'PREPARING')}
              className="w-full bg-[#b3247e] text-white py-2 rounded-xl font-bold hover:bg-[#8a1a60] transition"
            >
              Lancer préparation
            </button>
          ) : (
            <button 
              onClick={() => onStatusChange(order.id, 'READY')}
              className="w-full bg-[#54bb24] text-white py-2 rounded-xl font-bold hover:bg-[#449c1d] transition flex items-center justify-center gap-2"
            >
              <CheckCircle2 size={18} /> Prêt
            </button>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="p-6 h-[calc(100vh-64px)] grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 overflow-x-auto">
      <div className="flex flex-col gap-4 min-w-[300px]">
        <h2 className="text-xl font-black flex items-center gap-2 sticky top-0 bg-gray-50 py-2 z-10 uppercase tracking-tighter">
          En Cours <span className="text-sm bg-pink-100 text-[#b3247e] px-2 rounded-full">{pendingOrders.length}</span>
        </h2>
        <div className="space-y-4">
          {pendingOrders.map(order => <Ticket key={order.id} order={order} />)}
          {pendingOrders.length === 0 && (
            <div className="p-12 text-center text-gray-400">
              <CheckCircle2 className="mx-auto mb-2 opacity-20" size={48} />
              <p>Aucune commande</p>
            </div>
          )}
        </div>
      </div>

      <div className="flex flex-col gap-4 min-w-[300px]">
        <h2 className="text-xl font-black flex items-center gap-2 sticky top-0 bg-gray-50 py-2 z-10 uppercase tracking-tighter">
          Prêt pour retrait <span className="text-sm bg-green-100 text-[#54bb24] px-2 rounded-full">{readyOrders.length}</span>
        </h2>
        <div className="space-y-4">
          {readyOrders.map(order => (
            <div key={order.id} className="bg-white p-4 rounded-2xl border border-green-100 shadow-sm flex justify-between items-center animate-pulse">
              <div>
                <p className="font-black text-xl">#{order.orderNumber}</p>
                <p className="text-sm text-gray-500 font-bold">Prêt depuis {Math.floor((Date.now() - order.timestamp)/60000)}m</p>
              </div>
              <button 
                onClick={() => onStatusChange(order.id, 'SERVED')}
                className="bg-green-100 text-[#54bb24] px-4 py-2 rounded-xl font-black hover:bg-green-200 uppercase text-[10px] tracking-widest"
              >
                Servi
              </button>
            </div>
          ))}
          {readyOrders.length === 0 && (
            <div className="p-12 text-center text-gray-400">
              <p>Rien en attente</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default KDS;

