import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import KDS from './components/KDS';
import Inventory from './components/Inventory';
import CRM from './components/CRM';
import MenuManager from './components/MenuManager';
import SettingsView from './components/SettingsView';
import ExpensesView from './components/ExpensesView';
import { Order, CartItem, OrderStatus, Ingredient, Customer, PaymentMethod, ServiceMode, Purchase, Expense } from './types';
import { MOCK_ORDERS, INGREDIENTS, MOCK_CUSTOMERS } from './constants';
import { formatPrix } from './utils';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('pos');
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('molls_orders');
    return saved ? JSON.parse(saved) : MOCK_ORDERS;
  });
  const [ingredients, setIngredients] = useState<Ingredient[]>(() => {
    const saved = localStorage.getItem('molls_ingredients');
    return saved ? JSON.parse(saved) : INGREDIENTS;
  });
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('molls_customers');
    return saved ? JSON.parse(saved) : MOCK_CUSTOMERS;
  });
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('molls_expenses');
    return saved ? JSON.parse(saved) : [];
  });
  const [purchases, setPurchases] = useState<Purchase[]>([]);

  useEffect(() => {
    localStorage.setItem('molls_orders', JSON.stringify(orders));
    localStorage.setItem('molls_ingredients', JSON.stringify(ingredients));
    localStorage.setItem('molls_expenses', JSON.stringify(expenses));
  }, [orders, ingredients, expenses]);

  const handleAddPurchase = (p: Omit<Purchase, 'id'>) => {
    const newPurchase = { ...p, id: crypto.randomUUID() };
    setPurchases(prev => [...prev, newPurchase]);

    setIngredients(prev => prev.map(ing => {
      if (ing.id === p.ingredientId) {
        const totalQty = ing.currentStock + p.quantity;
        const totalValue = (ing.currentStock * ing.costPrice) + p.totalPrice;
        return {
          ...ing,
          currentStock: totalQty,
          costPrice: Number((totalValue / totalQty).toFixed(2))
        };
      }
      return ing;
    }));
  };

  const processStockReduction = (items: CartItem[]) => {
    setIngredients(prev => {
      const next = [...prev];
      items.forEach(item => {
        item.product.recipe.forEach(recipeItem => {
          const idx = next.findIndex(i => i.id === recipeItem.ingredientId);
          if (idx !== -1) {
            next[idx] = { ...next[idx], currentStock: Number((next[idx].currentStock - (recipeItem.quantity * item.quantity)).toFixed(2)) };
          }
        });
      });
      return next;
    });
  };

  const handleAddOrder = (items: CartItem[], total: number, paymentMethod: PaymentMethod, serviceMode: ServiceMode, customerId?: string) => {
    const newOrder: Order = {
      id: crypto.randomUUID(),
      orderNumber: `${orders.length + 101}`,
      timestamp: Date.now(),
      items,
      total,
      status: 'PENDING',
      paymentMethod,
      serviceMode,
      customerId
    };
    setOrders(prev => [newOrder, ...prev]);
    processStockReduction(items);
    if (customerId) {
      setCustomers(prev => prev.map(c => c.id === customerId ? {...c, loyaltyPoints: c.loyaltyPoints + Math.floor(total), lastVisit: Date.now()} : c));
    }
  };

  const handleAddExpense = (e: Omit<Expense, 'id'>) => {
    const newExpense: Expense = { ...e, id: crypto.randomUUID() };
    setExpenses(prev => [...prev, newExpense]);
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard orders={orders} ingredients={ingredients} expenses={expenses} onViewChange={setCurrentView} />;
      case 'pos': return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} />;
      case 'kds': return <KDS orders={orders} onStatusChange={(id, stat) => setOrders(prev => prev.map(o => o.id === id ? {...o, status: stat} : o))} />;
      case 'menu': return <MenuManager ingredients={ingredients} />;
      case 'inventory': return <Inventory ingredients={ingredients} onAddIngredient={() => {}} onAddPurchase={handleAddPurchase} />;
      case 'customers': return <CRM customers={customers} orders={orders} onAddCustomer={(c) => setCustomers(prev => [...prev, {...c, id: crypto.randomUUID(), loyaltyPoints: 0}])} />;
      case 'expenses': return <ExpensesView expenses={expenses} onAdd={handleAddExpense} />;
      case 'settings': return <SettingsView />;
      case 'reports':
        return (
          <div className="p-8 space-y-8 animate-in fade-in">
             <h1 className="text-3xl font-black text-gray-800 tracking-tighter uppercase">Historique des ventes</h1>
             <div className="bg-white rounded-[2.5rem] border border-gray-100 overflow-hidden shadow-sm">
                <table className="w-full text-left">
                  <thead className="bg-gray-50 font-black text-[10px] text-gray-400 uppercase tracking-widest border-b">
                    <tr><th className="px-8 py-6">Ticket</th><th className="px-8 py-6">Mode</th><th className="px-8 py-6">Paiement</th><th className="px-8 py-6 text-right">Total</th></tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {orders.map(o => (
                      <tr key={o.id} className="hover:bg-gray-50/50">
                        <td className="px-8 py-6 font-black">#{o.orderNumber}</td>
                        <td className="px-8 py-6 uppercase text-[10px] font-black">{o.serviceMode}</td>
                        <td className="px-8 py-6 text-gray-400 font-bold">{o.paymentMethod}</td>
                        <td className="px-8 py-6 text-right font-black text-lg">{formatPrix(o.total)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        );
      default: return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} />;
    }
  };

  return (
    <div className="flex h-screen bg-[#F1F3F6] text-gray-900 overflow-hidden font-['Inter']">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} />
      <main className="flex-1 overflow-hidden">{renderView()}</main>
    </div>
  );
};

