interface DashboardProps {
  orders: Order[];
  ingredients: Ingredient[];
  expenses: Expense[];
  onViewChange: (view: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ orders, ingredients, expenses, onViewChange }) => {
  const [showZReport, setShowZReport] = useState(false);

  const stats = useMemo(() => {
    const totalSales = orders.reduce((acc, o) => acc + o.total, 0);
    const orderCount = orders.length;
    const avgBasket = orderCount > 0 ? totalSales / orderCount : 0;
    const totalExpenses = expenses.reduce((acc, e) => acc + e.amountTTC, 0);
    const totalVAT = orders.reduce((acc, o) => {
      const { totalTVA } = calculerTotaux(o.items);
      return acc + totalTVA;
    }, 0);

    const hourlyData = Array.from({ length: 8 }, (_, i) => {
      const hour = 11 + i;
      return {
        name: `${hour}h`,
        sales: orders.filter(o => new Date(o.timestamp).getHours() === hour)
                     .reduce((acc, o) => acc + o.total, 0)
      };
    });
    return { totalSales, orderCount, avgBasket, totalExpenses, totalVAT, hourlyData };
  }, [orders, expenses]);

  const salesByType = useMemo(() => {
    const cash = orders.filter(o => o.paymentMethod === 'CASH').reduce((acc, o) => acc + o.total, 0);
    const card = orders.filter(o => o.paymentMethod === 'CARD').reduce((acc, o) => acc + o.total, 0);
    return { cash, card };
