            onClick={() => setShowZReport(true)}
            className="bg-white border-2 border-[#b3247e] text-[#b3247e] px-6 py-2.5 rounded-xl font-bold hover:bg-pink-50 transition flex items-center gap-2 uppercase text-xs tracking-widest"
