interface MenuManagerProps {
  ingredients: Ingredient[];
  products: Product[];
  onUpdateProducts: (products: Product[]) => void;
}

const MenuManager: React.FC<MenuManagerProps> = ({ ingredients, products, onUpdateProducts }) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [showModal, setShowModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product>>({
    name: '',
    price: 0,
    categoryId: '1',
    vatRate: 10,
    recipe: [],
    isAvailable: true,
    imageUrl: 'https://picsum.photos/seed/food/400/400'
  });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const newProduct = {
      ...editingProduct,
      id: editingProduct.id || crypto.randomUUID()
    } as Product;

    if (editingProduct.id) {
      onUpdateProducts(products.map(p => p.id === editingProduct.id ? newProduct : p));
    } else {
      onUpdateProducts([...products, newProduct]);
    }
    setShowModal(false);
    setSelectedProduct(newProduct);
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500 overflow-y-auto h-full scrollbar-hide">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-black text-gray-800 tracking-tighter uppercase">Menu & Recettes</h1>
          <p className="text-gray-500 font-medium">Configurez vos plats et analysez vos marges.</p>
