                  <div className="flex-1">
                    <h3 className="font-black text-gray-800 leading-tight">{product.name}</h3>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">
                      Prix : {formatPrix(product.price)}
