interface InventoryProps {
  ingredients: Ingredient[];
  onAddIngredient: (ingredient: Omit<Ingredient, 'id'>) => void;
  onAddPurchase: (purchase: Omit<Purchase, 'id'>) => void;
  onAddWaste: (waste: Omit<Waste, 'id'>) => void;
}

const Inventory: React.FC<InventoryProps> = ({ ingredients, onAddIngredient, onAddPurchase, onAddWaste }) => {
  const [showPurchaseModal, setShowPurchaseModal] = useState(false);
  const [showWasteModal, setShowWasteModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [newPurchase, setNewPurchase] = useState({ ingredientId: '', supplierName: '', quantity: 0, totalPrice: 0 });
  const [newWaste, setNewWaste] = useState<{ingredientId: string, quantity: number, reason: Waste['reason']}>({ ingredientId: '', quantity: 0, reason: 'Péremption' });

  const filteredIngredients = useMemo(() => {
    return ingredients.filter(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [ingredients, searchTerm]);

  const handlePurchaseSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPurchase.ingredientId || newPurchase.quantity <= 0) return;
    onAddPurchase({ ...newPurchase, date: Date.now() });
    setShowPurchaseModal(false);
    setNewPurchase({ ingredientId: '', supplierName: '', quantity: 0, totalPrice: 0 });
  };

  const handleWasteSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWaste.ingredientId || newWaste.quantity <= 0) return;
    onAddWaste({ ...newWaste, date: Date.now() });
    setShowWasteModal(false);
    setNewWaste({ ingredientId: '', quantity: 0, reason: 'Péremption' });
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in h-full overflow-y-auto scrollbar-hide">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-black text-gray-800 tracking-tighter uppercase">Stocks & Inventaire</h1>
          <p className="text-gray-500 font-medium">Suivi en temps réel et correction des stocks.</p>
        </div>
        <div className="flex gap-4">
          <button 
            onClick={() => setShowWasteModal(true)}
            className="bg-red-50 border-2 border-red-200 text-red-600 px-6 py-3.5 rounded-2xl font-black text-sm flex items-center gap-2 hover:bg-red-100 transition-colors"
          >
            <Trash2 size={18} /> Déclarer Perte
          </button>
          <button 
            onClick={() => setShowPurchaseModal(true)}
            className="bg-[#54bb24] text-white px-6 py-3.5 rounded-2xl font-black text-sm flex items-center gap-2 shadow-xl shadow-green-100 hover:scale-105 transition-transform"
          >
            <Truck size={18} /> Entrée Marchandise
          </button>
        </div>
      </header>

      {/* Alertes Critique */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {ingredients.filter(i => i.currentStock <= i.minStock).map(ing => (
          <div key={ing.id} className="bg-red-50 p-6 rounded-3xl border border-red-100 flex items-center gap-4 animate-in slide-in-from-top">
            <div className="p-3 bg-red-600 text-white rounded-2xl">
              <AlertTriangle size={20} />
            </div>
            <div>
              <p className="text-[10px] font-black text-red-600 uppercase tracking-widest">Seuil atteint</p>
              <p className="font-bold text-gray-800">{ing.name}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
            <input 
              type="text" 
              placeholder="Rechercher un ingrédient..." 
              className="w-full pl-12 pr-4 py-4 bg-gray-50 rounded-2xl border-none outline-none font-bold"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50/50 text-[10px] font-black text-gray-400 uppercase tracking-widest">
              <tr>
                <th className="px-8 py-6">Référence</th>
                <th className="px-8 py-6">Stock Actuel</th>
                <th className="px-8 py-6">Seuil Alerte</th>
                <th className="px-8 py-6">Valeur Unitaire</th>
                <th className="px-8 py-6 text-right">Valeur Totale</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {filteredIngredients.map(ing => (
                <tr key={ing.id} className="hover:bg-gray-50/50 transition-colors group">
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-gray-100 rounded-xl flex items-center justify-center text-gray-400 group-hover:bg-[#b3247e] group-hover:text-white transition-colors">
                        <Package size={20} />
                      </div>
                      <span className="font-black text-gray-800">{ing.name}</span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <span className={`text-lg font-black ${ing.currentStock <= ing.minStock ? 'text-red-600' : 'text-gray-900'}`}>
                      {ing.currentStock}
                    </span>
                    <span className="ml-1 text-[10px] font-black text-gray-400 uppercase">{ing.unit}</span>
                  </td>
                  <td className="px-8 py-6">
                    <span className="bg-gray-100 px-3 py-1 rounded-full text-xs font-bold text-gray-500">
                      {ing.minStock} {ing.unit}
                    </span>
                  </td>
                  <td className="px-8 py-6 font-bold text-gray-600">{formatPrix(ing.costPrice)}</td>
                  <td className="px-8 py-6 text-right font-black text-gray-900">{formatPrix(ing.currentStock * ing.costPrice)}</td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredIngredients.length === 0 && (
            <div className="p-20 text-center text-gray-400 italic">Aucun ingrédient trouvé.</div>
          )}
        </div>
      </div>

      {/* Modals remain the same but now functional in App.tsx */}
      {showWasteModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black flex items-center gap-3 tracking-tighter uppercase">
                <Trash2 className="text-red-600" /> Déclarer une perte
              </h2>
              <button onClick={() => setShowWasteModal(false)} className="text-gray-400 hover:text-gray-600"><X size={24} /></button>
            </div>
            <form onSubmit={handleWasteSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Ingrédient concerné</label>
                <select 
                  className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-red-500 font-bold"
                  value={newWaste.ingredientId}
                  onChange={e => setNewWaste({...newWaste, ingredientId: e.target.value})}
                >
                  <option value="">Sélectionner...</option>
                  {ingredients.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Quantité perdue</label>
                  <input type="number" step="0.01" className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-red-500 font-bold" value={newWaste.quantity} onChange={e => setNewWaste({...newWaste, quantity: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Motif</label>
                  <select className="w-full p-4 bg-gray-50 rounded-2xl outline-none font-bold" value={newWaste.reason} onChange={e => setNewWaste({...newWaste, reason: e.target.value as any})}>
                    <option>Péremption</option>
                    <option>Casse</option>
                    <option>Erreur</option>
                    <option>Autre</option>
                  </select>
                </div>
              </div>
              <button className="w-full bg-red-600 text-white py-5 rounded-[1.5rem] font-black text-sm uppercase tracking-widest shadow-xl shadow-red-100 transition-all active:scale-95">Soustraire du stock</button>
            </form>
          </div>
        </div>
      )}

      {showPurchaseModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black flex items-center gap-3 tracking-tighter uppercase">
                <Truck className="text-[#54bb24]" /> Nouvel Achat
              </h2>
              <button onClick={() => setShowPurchaseModal(false)} className="text-gray-400 hover:text-gray-600"><X size={24} /></button>
            </div>
            <form onSubmit={handlePurchaseSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Référence</label>
                <select 
                  className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-[#54bb24] font-bold"
                  value={newPurchase.ingredientId}
                  onChange={e => setNewPurchase({...newPurchase, ingredientId: e.target.value})}
                >
                  <option value="">Sélectionner...</option>
                  {ingredients.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Fournisseur</label>
                <input type="text" className="w-full p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Ex: Métro" value={newPurchase.supplierName} onChange={e => setNewPurchase({...newPurchase, supplierName: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Quantité</label>
                  <input type="number" step="0.01" className="w-full p-4 bg-gray-50 rounded-2xl outline-none font-bold" value={newPurchase.quantity} onChange={e => setNewPurchase({...newPurchase, quantity: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Prix Total (€)</label>
                  <input type="number" step="0.01" className="w-full p-4 bg-gray-50 rounded-2xl outline-none font-bold" value={newPurchase.totalPrice} onChange={e => setNewPurchase({...newPurchase, totalPrice: parseFloat(e.target.value)})} />
                </div>
              </div>
              <button className="w-full bg-[#54bb24] text-white py-5 rounded-[1.5rem] font-black text-sm uppercase tracking-widest shadow-xl shadow-green-100 transition-all active:scale-95">Ajouter au stock</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React from 'react';
import { Clock, CheckCircle2, AlertCircle } from 'lucide-react';
import { Order, OrderStatus, Product } from '../types';

interface KDSProps {
  orders: Order[];
  products: Product[];
  onStatusChange: (orderId: string, newStatus: OrderStatus) => void;
}

const KDS: React.FC<KDSProps> = ({ orders, products, onStatusChange }) => {
  const pendingOrders = orders.filter(o => o.status === 'PENDING' || o.status === 'PREPARING');
  const readyOrders = orders.filter(o => o.status === 'READY');

  const Ticket: React.FC<{ order: Order }> = ({ order }) => {
    const elapsed = Math.floor((Date.now() - order.timestamp) / 60000);
    const isLate = elapsed > 15;

    return (
      <div className={`bg-white rounded-2xl shadow-sm border-l-8 ${
        order.status === 'PREPARING' ? 'border-[#b3247e]' : 'border-[#54bb24]'
      } overflow-hidden`}>
        <div className="p-4 border-b border-gray-50 flex justify-between items-center">
          <div>
            <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">#{order.orderNumber}</span>
            <h4 className="font-black text-lg">Commande #{order.orderNumber}</h4>
          </div>
          <div className={`flex items-center gap-1 text-sm font-bold ${isLate ? 'text-red-500' : 'text-gray-500'}`}>
            <Clock size={16} /> {elapsed}m
          </div>
        </div>

        <div className="p-4 space-y-3">
          {order.items.map((item, idx) => {
            const product = products.find(p => p.id === item.productId);
            return (
              <div key={idx} className="flex justify-between items-start">
                <div className="flex gap-3">
                  <span className="w-6 h-6 flex items-center justify-center bg-gray-100 rounded text-sm font-bold">{item.quantity}</span>
                  <div className="flex flex-col">
                    <span className="font-bold text-gray-800">{product?.name || item.product.name}</span>
                    {item.isRedeemed && <span className="text-[9px] font-black text-[#54bb24] uppercase">🎁 Offert (Points)</span>}
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-3 bg-gray-50">
          {order.status === 'PENDING' ? (
            <button 
              onClick={() => onStatusChange(order.id, 'PREPARING')}
              className="w-full bg-[#b3247e] text-white py-2 rounded-xl font-bold hover:bg-[#8a1a60] transition"
            >
              Lancer préparation
            </button>
          ) : (
            <button 
              onClick={() => onStatusChange(order.id, 'READY')}
              className="w-full bg-[#54bb24] text-white py-2 rounded-xl font-bold hover:bg-[#449c1d] transition flex items-center justify-center gap-2"
            >
              <CheckCircle2 size={18} /> Prêt
            </button>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="p-6 h-[calc(100vh-64px)] grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 overflow-x-auto">
      <div className="flex flex-col gap-4 min-w-[300px]">
        <h2 className="text-xl font-black flex items-center gap-2 sticky top-0 bg-gray-50 py-2 z-10 uppercase tracking-tighter">
          En Cours <span className="text-sm bg-pink-100 text-[#b3247e] px-2 rounded-full">{pendingOrders.length}</span>
        </h2>
        <div className="space-y-4">
          {pendingOrders.map(order => <Ticket key={order.id} order={order} />)}
          {pendingOrders.length === 0 && (
            <div className="p-12 text-center text-gray-400">
              <CheckCircle2 className="mx-auto mb-2 opacity-20" size={48} />
              <p>Aucune commande</p>
            </div>
          )}
        </div>
      </div>

      <div className="flex flex-col gap-4 min-w-[300px]">
        <h2 className="text-xl font-black flex items-center gap-2 sticky top-0 bg-gray-50 py-2 z-10 uppercase tracking-tighter">
          Prêt pour retrait <span className="text-sm bg-green-100 text-[#54bb24] px-2 rounded-full">{readyOrders.length}</span>
        </h2>
        <div className="space-y-4">
          {readyOrders.map(order => (
            <div key={order.id} className="bg-white p-4 rounded-2xl border border-green-100 shadow-sm flex justify-between items-center animate-pulse">
              <div>
                <p className="font-black text-xl">#{order.orderNumber}</p>
                <p className="text-sm text-gray-500 font-bold">Prêt depuis {Math.floor((Date.now() - order.timestamp)/60000)}m</p>
              </div>
              <button 
                onClick={() => onStatusChange(order.id, 'SERVED')}
                className="bg-green-100 text-[#54bb24] px-4 py-2 rounded-xl font-black hover:bg-green-200 uppercase text-[10px] tracking-widest"
              >
                Servi
              </button>
            </div>
          ))}
          {readyOrders.length === 0 && (
            <div className="p-12 text-center text-gray-400">
              <p>Rien en attente</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default KDS;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import KDS from './components/KDS';
import Inventory from './components/Inventory';
import CRM from './components/CRM';
import MenuManager from './components/MenuManager';
import SettingsView from './components/SettingsView';
import ExpensesView from './components/ExpensesView';
import { Order, CartItem, OrderStatus, Ingredient, Customer, PaymentMethod, ServiceMode, Purchase, Expense, Waste, Product } from './types';
import { MOCK_ORDERS, INGREDIENTS, MOCK_CUSTOMERS, PRODUCTS } from './constants';
import { formatPrix, downloadCSV, formatDate } from './utils';
import { Lock, ArrowDownCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('pos');
  const [isLocked, setIsLocked] = useState(true);
  const [pin, setPin] = useState('');

  const [truckSettings, setTruckSettings] = useState(() => {
    const saved = localStorage.getItem('molls_settings');
    return saved ? JSON.parse(saved) : { name: "Molly's Truck", slogan: "Les meilleurs burgers de la ville !", tvaEmporter: 5.5, tvaPlace: 10 };
  });

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('molls_products');
    return saved ? JSON.parse(saved) : PRODUCTS;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('molls_orders');
    return saved ? JSON.parse(saved) : MOCK_ORDERS;
  });

  const [ingredients, setIngredients] = useState<Ingredient[]>(() => {
    const saved = localStorage.getItem('molls_ingredients');
    return saved ? JSON.parse(saved) : INGREDIENTS;
  });

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('molls_customers');
    return saved ? JSON.parse(saved) : MOCK_CUSTOMERS;
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('molls_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [wastes, setWastes] = useState<Waste[]>(() => {
    const saved = localStorage.getItem('molls_wastes');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('molls_orders', JSON.stringify(orders));
    localStorage.setItem('molls_ingredients', JSON.stringify(ingredients));
    localStorage.setItem('molls_expenses', JSON.stringify(expenses));
    localStorage.setItem('molls_customers', JSON.stringify(customers));
    localStorage.setItem('molls_products', JSON.stringify(products));
    localStorage.setItem('molls_settings', JSON.stringify(truckSettings));
    localStorage.setItem('molls_wastes', JSON.stringify(wastes));
  }, [orders, ingredients, expenses, customers, products, truckSettings, wastes]);

  const handleAddPurchase = (p: Omit<Purchase, 'id'>) => {
    setIngredients(prev => prev.map(ing => {
      if (ing.id === p.ingredientId) {
        const totalQty = ing.currentStock + p.quantity;
        const totalValue = (ing.currentStock * ing.costPrice) + p.totalPrice;
        return {
          ...ing,
          currentStock: Number(totalQty.toFixed(2)),
          costPrice: Number((totalValue / totalQty).toFixed(2))
        };
      }
      return ing;
    }));
  };

  const handleAddWaste = (w: Omit<Waste, 'id'>) => {
    const newWaste = { ...w, id: crypto.randomUUID() };
    setWastes(prev => [...prev, newWaste]);
    setIngredients(prev => prev.map(ing => {
      if (ing.id === w.ingredientId) {
        return { ...ing, currentStock: Number((ing.currentStock - w.quantity).toFixed(2)) };
      }
      return ing;
    }));
  };

  const processStockReduction = (items: CartItem[]) => {
    setIngredients(prev => {
      const next = [...prev];
      items.forEach(item => {
        item.product.recipe.forEach(recipeItem => {
          const idx = next.findIndex(i => i.id === recipeItem.ingredientId);
          if (idx !== -1) {
            next[idx] = { ...next[idx], currentStock: Number((next[idx].currentStock - (recipeItem.quantity * item.quantity)).toFixed(2)) };
          }
        });
      });
      return next;
    });
  };

  const handleAddOrder = (items: CartItem[], total: number, paymentMethod: PaymentMethod, serviceMode: ServiceMode, customerId?: string) => {
    const newOrder: Order = {
      id: crypto.randomUUID(),
      orderNumber: `${orders.length + 101}`,
      timestamp: Date.now(),
      items,
      total,
      status: 'PENDING',
      paymentMethod,
      serviceMode,
      customerId
    };
    setOrders(prev => [newOrder, ...prev]);
    processStockReduction(items);

    if (customerId) {
      setCustomers(prev => prev.map(c => {
        if (c.id === customerId) {
          const redeemedItemsCount = items.filter(i => i.isRedeemed).length;
          const pointsSpent = redeemedItemsCount * 100;
          const pointsEarned = Math.floor(total);
          return {
            ...c,
            loyaltyPoints: c.loyaltyPoints - pointsSpent + pointsEarned,
            lastVisit: Date.now()
          };
        }
        return c;
      }));
    }
  };

  const handlePinInput = (num: string) => {
    const newPin = pin + num;
    if (newPin === '1234') {
      setIsLocked(false);
      setPin('');
    } else if (newPin.length >= 4) {
      setPin('');
    } else {
      setPin(newPin);
    }
  };

  const exportOrders = () => {
    const data = orders.map(o => ({
      Ticket: o.orderNumber,
      Date: formatDate(o.timestamp, 'yyyy-MM-dd HH:mm'),
      Mode: o.serviceMode,
      Paiement: o.paymentMethod || 'Non spécifié',
      Total: o.total
    }));
    downloadCSV(data, 'ventes_mollys_truck');
  };

  if (isLocked) {
    return (
      <div className="h-screen w-screen bg-[#b3247e] flex items-center justify-center p-4">
        <div className="bg-white/10 backdrop-blur-3xl p-12 rounded-[3.5rem] border border-white/20 shadow-2xl flex flex-col items-center w-full max-sm:max-w-xs max-w-sm">
          <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center text-[#b3247e] mb-8 shadow-xl">
            <Lock size={32} />
          </div>
          <h2 className="text-white text-2xl font-black uppercase tracking-tighter mb-2">Accès Sécurisé</h2>
          <p className="text-white/60 font-bold text-xs uppercase tracking-widest mb-8 text-center">Entrez votre code PIN (1234)</p>

          <div className="flex gap-4 mb-10">
            {[0, 1, 2, 3].map(i => (
              <div key={i} className={`w-4 h-4 rounded-full border-2 border-white transition-all ${pin.length > i ? 'bg-white scale-125 shadow-lg shadow-white/50' : 'bg-transparent'}`}></div>
            ))}
          </div>

          <div className="grid grid-cols-3 gap-6 w-full">
            {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
              <button key={n} onClick={() => handlePinInput(n.toString())} className="w-full aspect-square rounded-2xl bg-white/10 text-white font-black text-2xl hover:bg-white hover:text-[#b3247e] transition-all active:scale-90">{n}</button>
            ))}
            <button className="col-start-2 aspect-square rounded-2xl bg-white/10 text-white font-black text-2xl hover:bg-white hover:text-[#b3247e] transition-all active:scale-90" onClick={() => handlePinInput('0')}>0</button>
          </div>
        </div>
      </div>
    );
  }

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard orders={orders} ingredients={ingredients} expenses={expenses} onViewChange={setCurrentView} />;
      case 'pos': return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} products={products} />;
      case 'kds': return <KDS orders={orders} products={products} onStatusChange={(id, stat) => setOrders(prev => prev.map(o => o.id === id ? {...o, status: stat} : o))} />;
      case 'menu': return <MenuManager ingredients={ingredients} products={products} onUpdateProducts={setProducts} />;
      case 'inventory': return <Inventory ingredients={ingredients} onAddIngredient={() => {}} onAddPurchase={handleAddPurchase} onAddWaste={handleAddWaste} />;
      case 'customers': return <CRM customers={customers} orders={orders} onAddCustomer={(c) => setCustomers(prev => [...prev, {...c, id: crypto.randomUUID(), loyaltyPoints: 0}])} />;
      case 'expenses': return <ExpensesView expenses={expenses} onAdd={(e) => setExpenses(prev => [...prev, {...e, id: crypto.randomUUID()}])} onDelete={(id) => setExpenses(prev => prev.filter(e => e.id !== id))} />;
      case 'settings': return <SettingsView settings={truckSettings} onUpdateSettings={setTruckSettings} onLock={() => setIsLocked(true)} />;
      case 'reports':
        return (
          <div className="p-8 space-y-8 animate-in fade-in overflow-y-auto h-full scrollbar-hide">
             <header className="flex justify-between items-end">
               <div>
                 <h1 className="text-3xl font-black text-gray-800 tracking-tighter uppercase">Historique des ventes</h1>
                 <p className="text-gray-500 font-medium">Consultez et exportez l'activité du truck.</p>
               </div>
               <button onClick={exportOrders} className="bg-white border-2 border-gray-200 text-gray-600 px-6 py-3 rounded-2xl font-black text-sm flex items-center gap-2 hover:bg-gray-50 transition-all">
                <ArrowDownCircle size={18} /> Export CSV
              </button>
             </header>
             <div className="bg-white rounded-[2.5rem] border border-gray-100 overflow-hidden shadow-sm">
                <table className="w-full text-left">
                  <thead className="bg-gray-50 font-black text-[10px] text-gray-400 uppercase tracking-widest border-b">
                    <tr><th className="px-8 py-6">Ticket</th><th className="px-8 py-6">Mode</th><th className="px-8 py-6">Paiement</th><th className="px-8 py-6 text-right">Total</th></tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {orders.length === 0 ? (
                      <tr><td colSpan={4} className="p-12 text-center text-gray-300 italic">Aucune vente enregistrée.</td></tr>
                    ) : orders.map(o => (
                      <tr key={o.id} className="hover:bg-gray-50/50">
                        <td className="px-8 py-6 font-black">#{o.orderNumber}</td>
                        <td className="px-8 py-6 uppercase text-[10px] font-black">{o.serviceMode}</td>
                        <td className="px-8 py-6 text-gray-400 font-bold">{o.paymentMethod || '-'}</td>
                        <td className="px-8 py-6 text-right font-black text-lg">{formatPrix(o.total)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        );
      default: return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} products={products} />;
    }
  };

  return (
    <div className="flex h-screen bg-[#F1F3F6] text-gray-900 overflow-hidden font-['Inter']">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} truckName={truckSettings.name} />
      <main className="flex-1 overflow-hidden relative">{renderView()}</main>
    </div>
  );
};

export default App;

export type Role = 'ADMIN' | 'MANAGER' | 'CASHIER' | 'KITCHEN';

export interface Category {
  id: string;
  name: string;
  color: string;
  ordre: number;
}

export interface Ingredient {
  id: string;
  name: string;
  unit: 'kg' | 'g' | 'L' | 'ml' | 'unit' | 'unité';
  currentStock: number;
  minStock: number;
  costPrice: number;
}

export interface Purchase {
  id: string;
  ingredientId: string;
  supplierName: string;
  date: number;
  quantity: number;
  totalPrice: number;
}

export interface Waste {
  id: string;
  ingredientId: string;
  quantity: number;
  reason: 'Péremption' | 'Casse' | 'Erreur' | 'Autre';
  date: number;
}

export interface RecipeItem {
  ingredientId: string;
  quantity: number;
}

// Added Variant interface for products
export interface Variant {
  id: string;
  name: string;
  priceExtra: number;
}

// Added Supplier interface
export interface Supplier {
  id: string;
  name: string;
  contact: string;
  phone: string;
  email: string;
}

export interface Product {
  id: string;
  categoryId: string;
  name: string;
  price: number;
  vatRate: number;
  recipe: RecipeItem[];
  imageUrl?: string;
  isAvailable: boolean;
  loyaltyPrice?: number; // Prix en points pour l'offrir
  variants?: Variant[]; // Added variants property to resolve type error in constants.tsx
}

export type OrderStatus = 'PENDING' | 'PREPARING' | 'READY' | 'SERVED' | 'CANCELLED';
export type ServiceMode = 'TAKEAWAY' | 'DINE_IN';
export type PaymentMethod = 'CASH' | 'CARD' | 'TR';

export interface CartItem {
  id: string;
  productId: string;
  product: Product;
  quantity: number;
  unitPrice: number;
  totalPrice: number;
  isRedeemed?: boolean; // Si l'article est offert via points
  selectedVariant?: Variant; // Option choisie (ex: Taille XL, sans oignons)
}

export interface Order {
  id: string;
  orderNumber: string;
  timestamp: number;
  items: CartItem[];
  total: number;
  status: OrderStatus;
  paymentMethod?: PaymentMethod;
  serviceMode: ServiceMode;
  customerId?: string;
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  email?: string;
  loyaltyPoints: number;
  lastVisit?: number;
}

export interface CalculTotaux {
  totalHT: number;
  totalTVA: number;
  totalTTC: number;
  detailTVA: {
    [key: string]: {
      baseHT: number;
      montantTVA: number;
    };
  };
}

export interface Expense {
  id: string;
  label: string;
  merchant: string;
  amountTTC: number;
  vatAmount: number;
  category: string;
  paymentMethod: 'Caisse (Espèces)' | 'Carte Pro' | 'Perso' | 'Virement';
  date: number;
  hasReceipt: boolean;
}

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import KDS from './components/KDS';
import Inventory from './components/Inventory';
import CRM from './components/CRM';
import MenuManager from './components/MenuManager';
import SettingsView from './components/SettingsView';
import ExpensesView from './components/ExpensesView';
import { Order, CartItem, OrderStatus, Ingredient, Customer, PaymentMethod, ServiceMode, Purchase, Expense, Waste, Product } from './types';
import { MOCK_ORDERS, INGREDIENTS, MOCK_CUSTOMERS, PRODUCTS } from './constants';
import { formatPrix, downloadCSV, formatDate } from './utils';
import { Lock, ArrowDownCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('pos');
  const [isLocked, setIsLocked] = useState(true);
  const [pin, setPin] = useState('');

  const [truckSettings, setTruckSettings] = useState(() => {
    const saved = localStorage.getItem('molls_settings');
    return saved ? JSON.parse(saved) : { name: "Molly's Truck", slogan: "Les meilleurs burgers de la ville !", tvaEmporter: 5.5, tvaPlace: 10 };
  });

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('molls_products');
    return saved ? JSON.parse(saved) : PRODUCTS;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('molls_orders');
    return saved ? JSON.parse(saved) : MOCK_ORDERS;
  });

  const [ingredients, setIngredients] = useState<Ingredient[]>(() => {
    const saved = localStorage.getItem('molls_ingredients');
    return saved ? JSON.parse(saved) : INGREDIENTS;
  });

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('molls_customers');
    return saved ? JSON.parse(saved) : MOCK_CUSTOMERS;
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('molls_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [wastes, setWastes] = useState<Waste[]>(() => {
    const saved = localStorage.getItem('molls_wastes');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('molls_orders', JSON.stringify(orders));
    localStorage.setItem('molls_ingredients', JSON.stringify(ingredients));
    localStorage.setItem('molls_expenses', JSON.stringify(expenses));
    localStorage.setItem('molls_customers', JSON.stringify(customers));
    localStorage.setItem('molls_products', JSON.stringify(products));
    localStorage.setItem('molls_settings', JSON.stringify(truckSettings));
    localStorage.setItem('molls_wastes', JSON.stringify(wastes));
  }, [orders, ingredients, expenses, customers, products, truckSettings, wastes]);

  const handleAddIngredient = (ing: Omit<Ingredient, 'id'>) => {
    setIngredients(prev => [...prev, { ...ing, id: crypto.randomUUID() }]);
  };

  const handleAddPurchase = (p: Omit<Purchase, 'id'>) => {
    setIngredients(prev => prev.map(ing => {
      if (ing.id === p.ingredientId) {
        const totalQty = ing.currentStock + p.quantity;
        const totalValue = (ing.currentStock * ing.costPrice) + p.totalPrice;
        return {
          ...ing,
          currentStock: Number(totalQty.toFixed(2)),
          costPrice: Number((totalValue / totalQty).toFixed(2))
        };
      }
      return ing;
    }));
  };

  const handleAddWaste = (w: Omit<Waste, 'id'>) => {
    const newWaste = { ...w, id: crypto.randomUUID() };
    setWastes(prev => [...prev, newWaste]);
    setIngredients(prev => prev.map(ing => {
      if (ing.id === w.ingredientId) {
        return { ...ing, currentStock: Number((ing.currentStock - w.quantity).toFixed(2)) };
      }
      return ing;
    }));
  };

  const processStockReduction = (items: CartItem[]) => {
    setIngredients(prev => {
      const next = [...prev];
      items.forEach(item => {
        item.product.recipe.forEach(recipeItem => {
          const idx = next.findIndex(i => i.id === recipeItem.ingredientId);
          if (idx !== -1) {
            next[idx] = { ...next[idx], currentStock: Number((next[idx].currentStock - (recipeItem.quantity * item.quantity)).toFixed(2)) };
          }
        });
      });
      return next;
    });
  };

  const handleAddOrder = (items: CartItem[], total: number, paymentMethod: PaymentMethod, serviceMode: ServiceMode, customerId?: string) => {
    const newOrder: Order = {
      id: crypto.randomUUID(),
      orderNumber: `${orders.length + 101}`,
      timestamp: Date.now(),
      items,
      total,
      status: 'PENDING',
      paymentMethod,
      serviceMode,
      customerId
    };
    setOrders(prev => [newOrder, ...prev]);
    processStockReduction(items);

    if (customerId) {
      setCustomers(prev => prev.map(c => {
        if (c.id === customerId) {
          const redeemedItemsCount = items.filter(i => i.isRedeemed).length;
          const pointsSpent = redeemedItemsCount * 100;
          const pointsEarned = Math.floor(total);
          return {
            ...c,
            loyaltyPoints: c.loyaltyPoints - pointsSpent + pointsEarned,
            lastVisit: Date.now()
          };
        }
        return c;
      }));
    }
  };

  const handlePinInput = (num: string) => {
    const newPin = pin + num;
    if (newPin === '1234') {
      setIsLocked(false);
      setPin('');
    } else if (newPin.length >= 4) {
      setPin('');
    } else {
      setPin(newPin);
    }
  };

  const exportOrders = () => {
    const data = orders.map(o => ({
      Ticket: o.orderNumber,
      Date: formatDate(o.timestamp, 'yyyy-MM-dd HH:mm'),
      Mode: o.serviceMode,
      Paiement: o.paymentMethod || 'Non spécifié',
      Total: o.total
    }));
    downloadCSV(data, 'ventes_mollys_truck');
  };

  if (isLocked) {
    return (
      <div className="h-screen w-screen bg-[#b3247e] flex items-center justify-center p-4">
        <div className="bg-white/10 backdrop-blur-3xl p-12 rounded-[3.5rem] border border-white/20 shadow-2xl flex flex-col items-center w-full max-sm:max-w-xs max-w-sm">
          <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center text-[#b3247e] mb-8 shadow-xl">
            <Lock size={32} />
          </div>
          <h2 className="text-white text-2xl font-black uppercase tracking-tighter mb-2">Accès Sécurisé</h2>
          <p className="text-white/60 font-bold text-xs uppercase tracking-widest mb-8 text-center">Entrez votre code PIN (1234)</p>

          <div className="flex gap-4 mb-10">
            {[0, 1, 2, 3].map(i => (
              <div key={i} className={`w-4 h-4 rounded-full border-2 border-white transition-all ${pin.length > i ? 'bg-white scale-125 shadow-lg shadow-white/50' : 'bg-transparent'}`}></div>
            ))}
          </div>

          <div className="grid grid-cols-3 gap-6 w-full">
            {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
              <button key={n} onClick={() => handlePinInput(n.toString())} className="w-full aspect-square rounded-2xl bg-white/10 text-white font-black text-2xl hover:bg-white hover:text-[#b3247e] transition-all active:scale-90">{n}</button>
            ))}
            <button className="col-start-2 aspect-square rounded-2xl bg-white/10 text-white font-black text-2xl hover:bg-white hover:text-[#b3247e] transition-all active:scale-90" onClick={() => handlePinInput('0')}>0</button>
          </div>
        </div>
      </div>
    );
  }

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard orders={orders} ingredients={ingredients} expenses={expenses} onViewChange={setCurrentView} />;
      case 'pos': return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} products={products} />;
      case 'kds': return <KDS orders={orders} products={products} onStatusChange={(id, stat) => setOrders(prev => prev.map(o => o.id === id ? {...o, status: stat} : o))} />;
      case 'menu': return <MenuManager ingredients={ingredients} products={products} onUpdateProducts={setProducts} />;
      case 'inventory': return <Inventory ingredients={ingredients} onAddIngredient={handleAddIngredient} onAddPurchase={handleAddPurchase} onAddWaste={handleAddWaste} />;
      case 'customers': return <CRM customers={customers} orders={orders} onAddCustomer={(c) => setCustomers(prev => [...prev, {...c, id: crypto.randomUUID(), loyaltyPoints: 0}])} />;
      case 'expenses': return <ExpensesView expenses={expenses} onAdd={(e) => setExpenses(prev => [...prev, {...e, id: crypto.randomUUID()}])} onDelete={(id) => setExpenses(prev => prev.filter(e => e.id !== id))} />;
      case 'settings': return <SettingsView settings={truckSettings} onUpdateSettings={setTruckSettings} onLock={() => setIsLocked(true)} />;
      case 'reports':
        return (
          <div className="p-8 space-y-8 animate-in fade-in overflow-y-auto h-full scrollbar-hide">
             <header className="flex justify-between items-end">
               <div>
                 <h1 className="text-3xl font-black text-gray-800 tracking-tighter uppercase">Historique des ventes</h1>
                 <p className="text-gray-500 font-medium">Consultez et exportez l'activité du truck.</p>
               </div>
               <button onClick={exportOrders} className="bg-white border-2 border-gray-200 text-gray-600 px-6 py-3 rounded-2xl font-black text-sm flex items-center gap-2 hover:bg-gray-50 transition-all">
                <ArrowDownCircle size={18} /> Export CSV
              </button>
             </header>
             <div className="bg-white rounded-[2.5rem] border border-gray-100 overflow-hidden shadow-sm">
                <table className="w-full text-left">
                  <thead className="bg-gray-50 font-black text-[10px] text-gray-400 uppercase tracking-widest border-b">
                    <tr><th className="px-8 py-6">Ticket</th><th className="px-8 py-6">Mode</th><th className="px-8 py-6">Paiement</th><th className="px-8 py-6 text-right">Total</th></tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {orders.length === 0 ? (
                      <tr><td colSpan={4} className="p-12 text-center text-gray-300 italic">Aucune vente enregistrée.</td></tr>
                    ) : orders.map(o => (
                      <tr key={o.id} className="hover:bg-gray-50/50">
                        <td className="px-8 py-6 font-black">#{o.orderNumber}</td>
                        <td className="px-8 py-6 uppercase text-[10px] font-black">{o.serviceMode}</td>
                        <td className="px-8 py-6 text-gray-400 font-bold">{o.paymentMethod || '-'}</td>
                        <td className="px-8 py-6 text-right font-black text-lg">{formatPrix(o.total)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        );
      default: return <POS ingredients={ingredients} customers={customers} onAddOrder={handleAddOrder} products={products} />;
    }
  };

  return (
    <div className="flex h-screen bg-[#F1F3F6] text-gray-900 overflow-hidden font-['Inter']">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} truckName={truckSettings.name} />
      <main className="flex-1 overflow-hidden relative">{renderView()}</main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, ShoppingCart, CreditCard, Banknote, UserCheck, UtensilsCrossed, Ticket, Truck, Gift, X, UserPlus, Info } from 'lucide-react';
import { CATEGORIES } from '../constants';
import { Product, CartItem, Ingredient, Customer, ServiceMode, PaymentMethod, Variant } from '../types';
import { calculerTotaux, formatPrix } from '../utils';

interface POSProps {
  ingredients: Ingredient[];
  customers: Customer[];
  products: Product[];
  onAddOrder: (items: CartItem[], total: number, paymentMethod: PaymentMethod, serviceMode: ServiceMode, customerId?: string) => void;
}

const POS: React.FC<POSProps> = ({ ingredients, customers, products, onAddOrder }) => {
  const [activeCategoryId, setActiveCategoryId] = useState<string>('all');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | undefined>();
  const [serviceMode, setServiceMode] = useState<ServiceMode>('TAKEAWAY');
  const [isPrinting, setIsPrinting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [variantSelector, setVariantSelector] = useState<Product | null>(null);

  const selectedCustomer = customers.find(c => c.id === selectedCustomerId);
  const totals = useMemo(() => calculerTotaux(cart), [cart]);

  const handleCheckout = (method: PaymentMethod) => {
    if (cart.length === 0) return;
    onAddOrder(cart, totals.totalTTC, method, serviceMode, selectedCustomerId);
    setCart([]);
    setSelectedCustomerId(undefined);
    setIsPrinting(true);
    setTimeout(() => setIsPrinting(false), 2000);
  };

  const addToCart = (product: Product, variant?: Variant) => {
    // Si le produit a des variantes et qu'aucune n'est sélectionnée, on ouvre la modale
    if (product.variants && product.variants.length > 0 && !variant) {
      setVariantSelector(product);
      return;
    }

    const variantId = variant?.id || 'standard';
    const existing = cart.find(item => 
      item.productId === product.id && 
      !item.isRedeemed && 
      (item.selectedVariant?.id || 'standard') === variantId
    );

    const unitPrice = product.price + (variant?.priceExtra || 0);

    if (existing) {
      setCart(prev => prev.map(item => 
        (item.productId === product.id && !item.isRedeemed && (item.selectedVariant?.id || 'standard') === variantId) 
        ? {...item, quantity: item.quantity + 1, totalPrice: (item.quantity + 1) * unitPrice} 
        : item
      ));
    } else {
      const newItem: CartItem = {
        id: crypto.randomUUID(),
        productId: product.id,
        product,
        quantity: 1,
        unitPrice: unitPrice,
        totalPrice: unitPrice,
        selectedVariant: variant
      };
      setCart(prev => [...prev, newItem]);
    }
    setVariantSelector(null);
  };

  const redeemWithPoints = (productId: string) => {
    const product = products.find(p => p.id === productId);
    if (!product || !selectedCustomer || selectedCustomer.loyaltyPoints < 100) return;

    const newItem: CartItem = {
      id: crypto.randomUUID(),
      productId: product.id,
      product,
      quantity: 1,
      unitPrice: 0,
      totalPrice: 0,
      isRedeemed: true
    };
    setCart(prev => [...prev, newItem]);
  };

  const removeFromCart = (cartItemId: string) => {
    setCart(prev => prev.filter(item => item.id !== cartItemId));
  };

  return (
    <div className="flex h-full overflow-hidden bg-[#F1F3F6]">
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <div className="bg-white p-4 border-b border-gray-200 flex justify-between items-center shrink-0">
          <div className="flex gap-2">
            <button 
              onClick={() => setActiveCategoryId('all')}
              className={`px-6 py-2 rounded-full text-[10px] font-black tracking-widest transition-all uppercase ${activeCategoryId === 'all' ? 'bg-[#b3247e] text-white shadow-lg' : 'bg-gray-100 text-gray-400 hover:bg-gray-200'}`}
            >
              Tous
            </button>
            {CATEGORIES.map(cat => (
              <button 
                key={cat.id} 
                onClick={() => setActiveCategoryId(cat.id)}
                className={`px-6 py-2 rounded-full text-[10px] font-black tracking-widest transition-all uppercase ${activeCategoryId === cat.id ? 'bg-[#b3247e] text-white shadow-lg' : 'bg-gray-100 text-gray-400 hover:bg-gray-200'}`}
              >
                {cat.name}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-3">
            {selectedCustomer ? (
              <div className="flex items-center gap-3 bg-pink-50 border border-[#b3247e]/20 px-4 py-2 rounded-2xl animate-in zoom-in-95">
                <div className="w-8 h-8 bg-[#b3247e] text-white rounded-xl flex items-center justify-center font-black text-xs">
                  {selectedCustomer.name.charAt(0)}
                </div>
                <div>
                  <p className="text-[10px] font-black text-gray-800 leading-none">{selectedCustomer.name}</p>
                  <p className="text-[9px] font-bold text-[#b3247e] uppercase mt-1">{selectedCustomer.loyaltyPoints} PTS</p>
                </div>
                <button onClick={() => setSelectedCustomerId(undefined)} className="ml-2 text-gray-400 hover:text-red-500">
                  <X size={16} />
                </button>
              </div>
            ) : (
              <div className="relative group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={14} />
                <input 
                  type="text" 
                  placeholder="Rechercher client..." 
                  className="pl-9 pr-4 py-2 bg-gray-100 border-none rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-[#b3247e] w-48 transition-all focus:w-64"
                  onChange={(e) => setSearchTerm(e.target.value)}
                  value={searchTerm}
                />
                {searchTerm && (
                  <div className="absolute top-full right-0 mt-2 w-64 bg-white rounded-2xl shadow-2xl border border-gray-100 z-50 max-h-60 overflow-y-auto">
                    {customers.filter(c => c.name.toLowerCase().includes(searchTerm.toLowerCase())).map(c => (
                      <button 
                        key={c.id}
                        onClick={() => { setSelectedCustomerId(c.id); setSearchTerm(''); }}
                        className="w-full text-left p-3 hover:bg-pink-50 flex items-center gap-3 border-b last:border-none"
                      >
                        <div className="w-8 h-8 bg-gray-100 rounded-lg flex items-center justify-center font-black text-xs">{c.name.charAt(0)}</div>
                        <div>
                          <p className="text-xs font-black">{c.name}</p>
                          <p className="text-[10px] text-gray-400 font-bold">{c.loyaltyPoints} pts</p>
                        </div>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="flex-1 p-8 overflow-y-auto grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6 content-start scrollbar-hide">
          {products.filter(p => activeCategoryId === 'all' || p.categoryId === activeCategoryId).map(product => (
            <div 
              key={product.id}
              className="bg-white rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-2xl transition-all text-left overflow-hidden group relative"
            >
              <button onClick={() => addToCart(product)} className="w-full text-left active:scale-95 transition-transform">
                <div className="aspect-square bg-gray-100 relative">
                  <img src={product.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                  <div className="absolute bottom-4 right-4 bg-white/95 backdrop-blur px-3 py-1 rounded-xl font-black text-sm shadow-xl text-[#54bb24]">
                    {formatPrix(product.price)}
                  </div>
                  {product.variants && product.variants.length > 0 && (
                    <div className="absolute top-4 right-4 bg-white/80 p-1.5 rounded-lg text-gray-500">
                      <Plus size={14} />
                    </div>
                  )}
                </div>
                <div className="p-5">
                  <h3 className="font-black text-gray-800 leading-tight">{product.name}</h3>
                </div>
              </button>

              {selectedCustomer && selectedCustomer.loyaltyPoints >= 100 && (
                <button 
                  onClick={() => redeemWithPoints(product.id)}
                  className="absolute top-4 left-4 bg-[#54bb24] text-white p-2 rounded-xl shadow-lg hover:scale-110 transition-all group/gift"
                  title="Offrir avec 100 points"
                >
                  <Gift size={16} />
                </button>
              )}
            </div>
          ))}
        </div>
      </div>

      <div className="w-96 bg-white border-l border-gray-200 flex flex-col shadow-2xl relative z-20">
        <div className="p-6 border-b border-gray-100 space-y-4">
          <div className="flex bg-gray-100 p-1.5 rounded-[1.5rem]">
            <button onClick={() => setServiceMode('TAKEAWAY')} className={`flex-1 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${serviceMode === 'TAKEAWAY' ? 'bg-white text-[#b3247e] shadow-sm' : 'text-gray-400'}`}>
              <Truck size={14} className="inline mr-2" /> Emporter
            </button>
            <button onClick={() => setServiceMode('DINE_IN')} className={`flex-1 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${serviceMode === 'DINE_IN' ? 'bg-white text-[#54bb24] shadow-sm' : 'text-gray-400'}`}>
              <UtensilsCrossed size={14} className="inline mr-2" /> Sur Place
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4 scrollbar-hide">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-300 gap-4 opacity-50">
              <ShoppingCart size={48} strokeWidth={1} />
              <p className="font-black text-[10px] uppercase tracking-widest">Panier Vide</p>
            </div>
          ) : cart.map(item => (
            <div key={item.id} className="flex justify-between items-center animate-in slide-in-from-right-4 group">
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => removeFromCart(item.id)}
                  className="w-8 h-8 flex items-center justify-center bg-gray-100 rounded-xl font-black text-xs hover:bg-red-50 hover:text-red-500 transition-colors"
                >
                  {item.quantity}
                </button>
                <div className="flex flex-col">
                  <div className="flex items-center gap-2">
                    <span className="font-bold text-gray-800 text-sm">{item.product.name}</span>
                    {item.selectedVariant && (
                      <span className="text-[10px] font-black text-[#b3247e] uppercase bg-pink-50 px-2 py-0.5 rounded">
                        {item.selectedVariant.name}
                      </span>
                    )}
                  </div>
                  {item.isRedeemed && <span className="text-[9px] font-black text-[#54bb24] uppercase">🎁 Offert (Points)</span>}
                </div>
              </div>
              <span className={`font-black text-sm ${item.isRedeemed ? 'text-[#54bb24]' : 'text-gray-800'}`}>
                {item.isRedeemed ? 'Gratuit' : formatPrix(item.totalPrice)}
              </span>
            </div>
          ))}
        </div>

        <div className="p-8 bg-gray-50 border-t border-gray-200 rounded-t-[3rem] space-y-6 shadow-[0_-20px_50px_-12px_rgba(0,0,0,0.05)]">
          <div className="space-y-2">
            <div className="flex justify-between text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">
              <span>TVA (Incluse)</span>
              <span>{formatPrix(totals.totalTVA)}</span>
            </div>
            <div className="flex justify-between items-end px-1">
              <span className="font-black text-gray-400 text-xs uppercase tracking-widest">Total</span>
              <span className="text-4xl font-black text-[#b3247e] tracking-tighter">{formatPrix(totals.totalTTC)}</span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => handleCheckout('CARD')} disabled={cart.length === 0} className="bg-[#b3247e] text-white p-5 rounded-3xl font-black text-[10px] uppercase tracking-widest flex flex-col items-center gap-2 hover:bg-[#8a1a60] transition-all active:scale-95 disabled:opacity-50 shadow-lg shadow-pink-100">
              <CreditCard size={24} /> Carte Bancaire
            </button>
            <button onClick={() => handleCheckout('CASH')} disabled={cart.length === 0} className="bg-[#54bb24] text-white p-5 rounded-3xl font-black text-[10px] uppercase tracking-widest flex flex-col items-center gap-2 hover:bg-[#449c1d] transition-all active:scale-95 disabled:opacity-50 shadow-lg shadow-green-100">
              <Banknote size={24} /> Espèces
            </button>
          </div>
        </div>

        {isPrinting && (
          <div className="absolute inset-0 bg-white/90 backdrop-blur-sm flex flex-col items-center justify-center animate-in fade-in z-50">
            <div className="w-16 h-16 border-4 border-[#b3247e] border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="font-black text-[#b3247e] uppercase tracking-[0.2em] text-xs">Impression ticket...</p>
          </div>
        )}
      </div>

      {/* Modale Sélecteur de Variantes */}
      {variantSelector && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-sm p-10 shadow-2xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black text-gray-800 tracking-tighter uppercase">Options</h2>
              <button onClick={() => setVariantSelector(null)} className="p-2 hover:bg-gray-100 rounded-full"><X size={20} /></button>
            </div>
            <p className="text-gray-500 font-medium mb-8">Choisissez une option pour {variantSelector.name}</p>
            <div className="space-y-4">
              <button 
                onClick={() => addToCart(variantSelector)}
                className="w-full p-4 bg-gray-50 hover:bg-gray-100 rounded-2xl flex justify-between items-center transition-all group"
              >
                <span className="font-black text-gray-800 uppercase text-xs tracking-widest">Standard</span>
                <span className="font-bold text-gray-400">Gratuit</span>
              </button>
              {variantSelector.variants?.map(variant => (
                <button 
                  key={variant.id}
                  onClick={() => addToCart(variantSelector, variant)}
                  className="w-full p-4 bg-pink-50/50 hover:bg-pink-100 rounded-2xl flex justify-between items-center transition-all border border-[#b3247e]/10 group"
                >
                  <span className="font-black text-[#b3247e] uppercase text-xs tracking-widest">{variant.name}</span>
                  <span className="font-black text-gray-800">+{formatPrix(variant.priceExtra)}</span>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;
